import { Injectable, Logger, OnApplicationBootstrap } from '@nestjs/common';
import { InjectDataSource } from '@nestjs/typeorm';
import { DataSource } from 'typeorm';
import { CommunityRoleSeederService } from '../../modules/community/services/community-role-seeder.service';

@Injectable()
export class DatabaseInitializerService implements OnApplicationBootstrap {
  private readonly logger = new Logger(DatabaseInitializerService.name);

  constructor(
    @InjectDataSource()
    private readonly dataSource: DataSource,
    private readonly roleSeeder: CommunityRoleSeederService,
  ) {}

  async onApplicationBootstrap(): Promise<void> {
    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();

    try {
      // Clean up legacy orphan tables
      try {
        await queryRunner.query(`DROP TABLE IF EXISTS "post_likes" CASCADE`);
        await queryRunner.query(
          `DROP TABLE IF EXISTS "interaction_events" CASCADE`,
        );
        await queryRunner.query(
          `DROP TABLE IF EXISTS "user_interactions" CASCADE`,
        );
        await queryRunner.query(
          `DROP TABLE IF EXISTS "feed_impressions" CASCADE`,
        );
      } catch (err: unknown) {
        this.logger.warn('Failed to clean up legacy orphan tables', err);
      }

      // Synchronize database schema once on server boot if needed
      await this.dataSource.synchronize();

      // Ensure all existing users have a role assigned
      try {
        await queryRunner.query(
          `UPDATE users_auth SET role = 'INDIVIDUAL' WHERE role IS NULL`,
        );
      } catch (err: any) {
        this.logger.warn(`Database backfill notice: ${err.message}`);
      }

      // Backfill missing relational logs from user_post_state
      try {
        await queryRunner.query(`
          INSERT INTO post_saves ("id", "userId", "postId", "createdAt")
          SELECT gen_random_uuid(), "userId", "postId", CURRENT_TIMESTAMP
          FROM user_post_state
          WHERE "hasSaved" = true
          ON CONFLICT ("postId", "userId") DO NOTHING;
        `);
      } catch (err: any) {
        this.logger.warn(
          `Database backfill notice for relational logs: ${err.message}`,
        );
      }

      // ─────────────────────────────────────────────────────────────────────────
      // CHAT INTEGRITY MIGRATION
      // Fixes duplicate DIRECT conversations caused by the race condition bug.
      // For each group of duplicate conversations (same participant pair):
      //   1. Identify the canonical conversation (the one with most messages, or most recent)
      //   2. Move all messages from orphan conversations to the canonical one
      //   3. Build the participantKey for the canonical conversation
      //   4. Delete orphan conversations (participants cascade)
      //   5. Add the unique constraint on participantKey
      // ─────────────────────────────────────────────────────────────────────────
      try {
        await this.runChatIntegrityMigration();
      } catch (err: any) {
        this.logger.warn(`Chat integrity migration notice: ${err.message}`);
      }

      // ─────────────────────────────────────────────────────────────────────────
      // COMMUNITY CATEGORY SEEDING
      // Seed default categories for Community Galaxy
      // ─────────────────────────────────────────────────────────────────────────
      try {
        await this.seedCommunityCategories();
      } catch (err: any) {
        this.logger.warn(`Community category seed notice: ${err.message}`);
      }

      // ─────────────────────────────────────────────────────────────────────────
      // COMMUNITY ROLE SEEDING
      // Seed default system roles strictly after synchronize()
      // ─────────────────────────────────────────────────────────────────────────
      try {
        await this.roleSeeder.seedSystemRoles();
      } catch (err: any) {
        this.logger.warn(`Community role seed notice: ${err.message}`);
      }
    } catch (error) {
      this.logger.error(
        'Failed to initialize database tables on startup:',
        error,
      );
      throw error;
    } finally {
      await queryRunner.release();
    }
  }

  private async runChatIntegrityMigration(): Promise<void> {
    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();
    try {
      // Step 1: Add participantKey column if it doesn't exist
      await queryRunner.query(`
        ALTER TABLE chat_conversations
        ADD COLUMN IF NOT EXISTS "participantKey" VARCHAR(100)
      `);

      // Step 2: Find all DIRECT conversations grouped by their participant pairs
      // For each pair, find the canonical conversation (has most messages; tie-break by oldest createdAt)
      const duplicateGroups = await queryRunner.query(`
        SELECT
          string_agg(c.id::text, ',' ORDER BY
            (SELECT COUNT(*) FROM chat_messages m WHERE m."conversationId" = c.id) DESC,
            c."createdAt" ASC
          ) AS conv_ids,
          string_agg(p."userId"::text, ':' ORDER BY p."userId"::text ASC) AS participant_key,
          COUNT(c.id) AS conv_count
        FROM chat_conversations c
        JOIN chat_participants p ON p."conversationId" = c.id
        WHERE c.type = 'DIRECT'
        GROUP BY c.id
        HAVING COUNT(p.id) = 2
      `);

      // Re-group by participant key to find duplicates
      const groupsByKey: Record<string, string[]> = {};
      for (const row of duplicateGroups) {
        const key = row.participant_key;
        const id = row.conv_ids.split(',')[0]; // first is canonical (most messages, oldest)
        if (!groupsByKey[key]) groupsByKey[key] = [];
        groupsByKey[key].push(id);
      }

      // Collect all conversations per participant key
      const allConvsByKey = await queryRunner.query(`
        SELECT
          c.id,
          c."createdAt",
          (SELECT COUNT(*) FROM chat_messages m WHERE m."conversationId" = c.id) AS msg_count,
          (
            SELECT string_agg(p."userId"::text, ':' ORDER BY p."userId"::text ASC)
            FROM chat_participants p
            WHERE p."conversationId" = c.id
          ) AS participant_key
        FROM chat_conversations c
        WHERE c.type = 'DIRECT'
        ORDER BY participant_key, msg_count DESC, c."createdAt" ASC
      `);

      // Group conversations by participant key
      const convsByParticipantKey: Record<string, any[]> = {};
      for (const row of allConvsByKey) {
        if (!row.participant_key) continue;
        if (!convsByParticipantKey[row.participant_key])
          convsByParticipantKey[row.participant_key] = [];
        convsByParticipantKey[row.participant_key].push(row);
      }

      let mergedCount = 0;
      let deletedCount = 0;

      for (const [participantKey, convs] of Object.entries(
        convsByParticipantKey,
      )) {
        if (convs.length === 0) continue;

        // The canonical conversation is the one with the most messages (first after ORDER BY)
        const canonical = convs[0];
        const orphans = convs.slice(1);

        // Set participantKey on canonical
        await queryRunner.query(
          `UPDATE chat_conversations SET "participantKey" = $1 WHERE id = $2`,
          [participantKey, canonical.id],
        );

        // Move messages from orphans to canonical
        for (const orphan of orphans) {
          const moved = await queryRunner.query(
            `UPDATE chat_messages SET "conversationId" = $1 WHERE "conversationId" = $2`,
            [canonical.id, orphan.id],
          );
          mergedCount += moved[1] ?? 0;

          // Merge participant lastReadAt state (take the most recent)
          await queryRunner.query(
            `
            UPDATE chat_participants cp_canonical
            SET "lastReadAt" = GREATEST(
              cp_canonical."lastReadAt",
              (SELECT cp_orphan."lastReadAt"
               FROM chat_participants cp_orphan
               WHERE cp_orphan."conversationId" = $1
                 AND cp_orphan."userId" = cp_canonical."userId"
               LIMIT 1)
            )
            WHERE cp_canonical."conversationId" = $2
          `,
            [orphan.id, canonical.id],
          );

          // Delete orphan conversation (participants cascade via FK)
          await queryRunner.query(
            `DELETE FROM chat_participants WHERE "conversationId" = $1`,
            [orphan.id],
          );
          await queryRunner.query(
            `DELETE FROM chat_conversations WHERE id = $1`,
            [orphan.id],
          );
          deletedCount++;
        }

        // Recalculate lastMessage summary on canonical after merge
        await queryRunner.query(
          `
          UPDATE chat_conversations SET
            "lastMessageId" = (SELECT id FROM chat_messages WHERE "conversationId" = $1 ORDER BY "createdAt" DESC LIMIT 1),
            "lastMessageText" = (SELECT LEFT(text, 100) FROM chat_messages WHERE "conversationId" = $1 AND "isDeleted" = false ORDER BY "createdAt" DESC LIMIT 1),
            "lastMessageSenderId" = (SELECT "senderId" FROM chat_messages WHERE "conversationId" = $1 ORDER BY "createdAt" DESC LIMIT 1),
            "lastMessageAt" = (SELECT "createdAt" FROM chat_messages WHERE "conversationId" = $1 ORDER BY "createdAt" DESC LIMIT 1)
          WHERE id = $1
        `,
          [canonical.id],
        );
      }

      // Step 3: Add unique constraint on participantKey (partial — only where not null)
      try {
        await queryRunner.query(`
          CREATE UNIQUE INDEX IF NOT EXISTS "UQ_chat_conversations_participantKey"
          ON chat_conversations ("participantKey")
          WHERE "participantKey" IS NOT NULL
        `);
      } catch (err: any) {
        // Index may already exist — that's fine
      }

      if (deletedCount > 0) {
      } else {
      }
    } finally {
      await queryRunner.release();
    }
  }

  private async seedCommunityCategories(): Promise<void> {
    const queryRunner = this.dataSource.createQueryRunner();
    await queryRunner.connect();
    try {
      const categories = [
        {
          id: '11111111-1111-4111-8111-111111111111',
          name: 'Adventure',
          slug: 'adventure',
        },
        {
          id: '22222222-2222-4222-8222-222222222222',
          name: 'Food & Eats',
          slug: 'food-eats',
        },
        {
          id: '33333333-3333-4333-8333-333333333333',
          name: 'Photography',
          slug: 'photography',
        },
        {
          id: '44444444-4444-4444-8444-444444444444',
          name: 'Storytelling',
          slug: 'storytelling',
        },
        {
          id: '55555555-5555-4555-8555-555555555555',
          name: 'Travel & Nomads',
          slug: 'travel-nomads',
        },
        {
          id: '66666666-6666-4666-8666-666666666666',
          name: 'Fitness & Runs',
          slug: 'fitness-runs',
        },
        {
          id: '77777777-7777-4777-8777-777777777777',
          name: 'Learning & Craft',
          slug: 'learning-craft',
        },
        {
          id: '88888888-8888-4888-8888-888888888888',
          name: 'Nightlife',
          slug: 'nightlife',
        },
      ];

      for (const cat of categories) {
        await queryRunner.query(
          `
          INSERT INTO community_categories (id, name, slug)
          VALUES ($1, $2, $3)
          ON CONFLICT (slug) DO UPDATE SET id = EXCLUDED.id
        `,
          [cat.id, cat.name, cat.slug],
        );
      }
    } finally {
      await queryRunner.release();
    }
  }
}

import { ValidationPipe } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { NestFactory } from '@nestjs/core';
import * as dns from 'dns';
import { AppModule } from './app.module';

// FIX for Node 18+ Docker IPv6 resolution ETIMEDOUT bugs
dns.setDefaultResultOrder('ipv4first');

async function bootstrap() {
  const app = await NestFactory.create(AppModule);
  const configService = app.get(ConfigService);

  // Configure Global CORS Policy
  const corsOrigins = configService.get<string[]>('app.corsOrigins', [
    'http://localhost:3000',
    'http://localhost:5173',
  ]);

  app.enableCors({
    origin:
      corsOrigins.length > 0 && corsOrigins[0] !== '' ? corsOrigins : true,
    methods: ['GET', 'POST', 'PUT', 'PATCH', 'DELETE', 'OPTIONS'],
    allowedHeaders: [
      'Content-Type',
      'Authorization',
      'Accept',
      'X-Requested-With',
    ],
    credentials: true,
  });

  // Global API Routing Prefix
  const apiPrefix = configService.get<string>('app.apiPrefix', 'api/v1');
  app.setGlobalPrefix(apiPrefix, {
    // Health check must be reachable at /api/v1/health — do NOT exclude it
  });

  // Global Validation Pipe for DTO Class Validation
  app.useGlobalPipes(
    new ValidationPipe({
      whitelist: true,
      transform: true,
      forbidNonWhitelisted: false,
    }),
  );

  // Enable graceful shutdown hooks for container management (ECS/K8s)
  // Handles SIGTERM/SIGINT so in-flight requests complete before exit
  app.enableShutdownHooks();

  const port = configService.get<number>('app.port', 5000);
  await app.listen(port, '0.0.0.0'); // Bind to all interfaces, required in containers
}
bootstrap();

import {
  Body,
  Controller,
  Get,
  HttpCode,
  HttpStatus,
  Param,
  Post,
  Req,
  UseGuards,
} from '@nestjs/common';
import { Request } from 'express';
import { RegisterRequestDto } from '../dto/register-request.dto';
import { LoginRequestDto } from '../dto/login-request.dto';
import { GoogleAuthRequestDto } from '../dto/google-auth-request.dto';
import { RefreshTokenRequestDto } from '../dto/refresh-token-request.dto';
import { AuthResponseDto } from '../dto/auth-response.dto';
import { AuthService } from '../services/auth.service';
import { JwtAuthGuard } from '../guards/jwt-auth.guard';
import { UserSessionEntity } from '../entities/user-session.entity';
import { RequestWithUser } from '../../../core/interfaces/request-with-user.interface';

@Controller('auth')
export class AuthController {
  constructor(private readonly authService: AuthService) {}

  @Post('register')
  @HttpCode(HttpStatus.CREATED)
  async register(
    @Body() dto: RegisterRequestDto,
    @Req() req: Request,
  ): Promise<AuthResponseDto> {
    const ip =
      req.ip || (req.headers['x-forwarded-for'] as string) || '127.0.0.1';
    const userAgent = req.headers['user-agent'] || 'Unknown';
    return this.authService.register(dto, ip, userAgent);
  }

  @Post('verify-email')
  @HttpCode(HttpStatus.OK)
  async verifyEmail(
    @Body('email') email: string,
    @Body('code') code: string,
  ): Promise<{ verified: boolean; message: string }> {
    return this.authService.verifyEmailCode(email, code);
  }

  @Post('resend-verification')
  @HttpCode(HttpStatus.OK)
  async resendVerification(
    @Body('email') email: string,
  ): Promise<{ success: boolean; message: string }> {
    return this.authService.resendVerificationCode(email);
  }

  @Post('login')
  @HttpCode(HttpStatus.OK)
  async login(
    @Body() dto: LoginRequestDto,
    @Req() req: Request,
  ): Promise<AuthResponseDto> {
    const ip =
      req.ip || (req.headers['x-forwarded-for'] as string) || '127.0.0.1';
    const userAgent = req.headers['user-agent'] || 'Unknown';
    return this.authService.login(dto, ip, userAgent);
  }

  @Post('google')
  @HttpCode(HttpStatus.OK)
  async googleAuth(
    @Body() dto: GoogleAuthRequestDto,
    @Req() req: Request,
  ): Promise<AuthResponseDto> {
    const ip =
      req.ip || (req.headers['x-forwarded-for'] as string) || '127.0.0.1';
    const userAgent = req.headers['user-agent'] || 'Unknown';
    return this.authService.googleAuth(dto, ip, userAgent);
  }

  @Post('refresh')
  @HttpCode(HttpStatus.OK)
  async refreshToken(
    @Body() dto: RefreshTokenRequestDto,
    @Req() req: Request,
  ): Promise<AuthResponseDto> {
    const ip =
      req.ip || (req.headers['x-forwarded-for'] as string) || '127.0.0.1';
    const userAgent = req.headers['user-agent'] || 'Unknown';
    return this.authService.refreshToken(dto, ip, userAgent);
  }

  @Post('logout')
  @HttpCode(HttpStatus.OK)
  async logout(
    @Body('userId') userId: string,
    @Body('refreshToken') refreshToken?: string,
  ): Promise<{ message: string }> {
    await this.authService.logout(userId, refreshToken);
    return { message: 'Successfully logged out and session revoked.' };
  }

  @Get('sessions')
  @UseGuards(JwtAuthGuard)
  async getActiveSessions(@Req() req: RequestWithUser): Promise<any[]> {
    const sessions = await this.authService.getActiveSessions(req.user.userId);
    return sessions.map((sess) => ({
      ...sess,
      isCurrent: sess.id === (req.user.sessionId as string),
    }));
  }

  @Post('sessions/revoke/:sessionId')
  @HttpCode(HttpStatus.OK)
  @UseGuards(JwtAuthGuard)
  async revokeSession(
    @Req() req: RequestWithUser,
    @Param('sessionId') sessionId: string,
  ): Promise<{ message: string }> {
    await this.authService.revokeSessionById(req.user.userId, sessionId);
    return { message: 'Session successfully revoked.' };
  }

  @Post('sessions/revoke-others')
  @HttpCode(HttpStatus.OK)
  @UseGuards(JwtAuthGuard)
  async revokeOtherSessions(
    @Req() req: RequestWithUser,
  ): Promise<{ message: string }> {
    await this.authService.revokeOtherSessions(
      req.user.userId,
      req.user.sessionId as string,
    );
    return { message: 'All other device sessions successfully revoked.' };
  }

  @Post('sessions/revoke-all')
  @HttpCode(HttpStatus.OK)
  @UseGuards(JwtAuthGuard)
  async revokeAllSessions(
    @Req() req: RequestWithUser,
  ): Promise<{ message: string }> {
    await this.authService.revokeAllSessions(req.user.userId);
    return { message: 'All active device sessions successfully revoked.' };
  }
}

import { Injectable } from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';

@Injectable()
export class OptionalJwtAuthGuard extends AuthGuard('jwt') {
  handleRequest(err, user, info, context) {
    if (err || !user) {
      return null;
    }
    return user;
  }
}

import {
  BadRequestException,
  ConflictException,
  Injectable,
  Logger,
  UnauthorizedException,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import * as bcrypt from 'bcrypt';
import { createHash, randomUUID } from 'crypto';
import { AuthResponseDto, AuthUserDto } from '../dto/auth-response.dto';
import { GoogleAuthRequestDto } from '../dto/google-auth-request.dto';
import { LoginRequestDto } from '../dto/login-request.dto';
import { RefreshTokenRequestDto } from '../dto/refresh-token-request.dto';
import { RegisterRequestDto } from '../dto/register-request.dto';
import { UserAuthEntity } from '../entities/user-auth.entity';
import { UserSessionEntity } from '../entities/user-session.entity';
import { AccountStatus } from '../enums/account-status.enum';
import { UserRole } from '../enums/user-role.enum';
import { IAuthService } from '../interfaces/auth-service.interface';
import { AuthRepository } from '../repositories/auth.repository';
import { MailService } from './mail.service';

@Injectable()
export class AuthService implements IAuthService {
  private readonly logger = new Logger(AuthService.name);

  constructor(
    private readonly authRepository: AuthRepository,
    private readonly mailService: MailService,
    private readonly jwtService: JwtService,
  ) {}

  async register(
    dto: RegisterRequestDto,
    ipAddress?: string,
    userAgent?: string,
  ): Promise<AuthResponseDto> {
    const existing = await this.authRepository.findByEmail(dto.email);
    if (existing) {
      throw new ConflictException(
        'An account with this email address already exists.',
      );
    }

    const saltRounds = 10;
    const passwordHash = await bcrypt.hash(dto.password, saltRounds);
    const userId = randomUUID();

    const verificationCode = Math.floor(
      100000 + Math.random() * 900000,
    ).toString();
    const verificationCodeExpiresAt = new Date(Date.now() + 15 * 60 * 1000); // 15 mins

    const newAuthUser = new UserAuthEntity({
      id: userId,
      email: dto.email.toLowerCase(),
      passwordHash,
      displayName: dto.name,
      role: UserRole.INDIVIDUAL,
      accountStatus: AccountStatus.PROFILE_INCOMPLETE,
      isEmailVerified: false,
      verificationCode,
      verificationCodeExpiresAt,
      createdAt: new Date(),
      updatedAt: new Date(),
    });

    await this.authRepository.create(newAuthUser);

    await this.mailService.sendVerificationCode(
      dto.email,
      dto.name,
      verificationCode,
    );

    return this.createSessionAndTokens(
      newAuthUser,
      dto.name,
      ipAddress,
      userAgent,
    );
  }

  async verifyEmailCode(
    email: string,
    code: string,
  ): Promise<{ verified: boolean; message: string }> {
    const user = await this.authRepository.findByEmail(email);
    if (!user) {
      throw new BadRequestException('User not found.');
    }

    if (user.isEmailVerified) {
      return { verified: true, message: 'Email is already verified.' };
    }

    if (
      !user.verificationCode ||
      user.verificationCode !== code ||
      (user.verificationCodeExpiresAt &&
        user.verificationCodeExpiresAt < new Date())
    ) {
      this.logger.warn(
        `Email verification failed for ${email}: Invalid or expired code`,
      );
      throw new BadRequestException('Invalid or expired verification code.');
    }

    user.isEmailVerified = true;
    user.verificationCode = undefined;
    user.verificationCodeExpiresAt = undefined;
    await this.authRepository.updateUser(user);

    return { verified: true, message: 'Email successfully verified.' };
  }

  async resendVerificationCode(
    email: string,
  ): Promise<{ success: boolean; message: string }> {
    const user = await this.authRepository.findByEmail(email);
    if (!user) {
      throw new BadRequestException('User account not found.');
    }

    if (user.isEmailVerified) {
      return { success: true, message: 'Email is already verified.' };
    }

    const verificationCode = Math.floor(
      100000 + Math.random() * 900000,
    ).toString();
    user.verificationCode = verificationCode;
    user.verificationCodeExpiresAt = new Date(Date.now() + 15 * 60 * 1000); // 15 mins
    user.updatedAt = new Date();

    await this.authRepository.updateUser(user);

    const displayName = user.displayName || 'Explorer';
    await this.mailService.sendVerificationCode(
      email,
      displayName,
      verificationCode,
    );

    return { success: true, message: 'Verification code successfully resent.' };
  }

  async login(
    dto: LoginRequestDto,
    ipAddress?: string,
    userAgent?: string,
  ): Promise<AuthResponseDto> {
    const user = await this.authRepository.findByEmail(dto.email);
    if (!user || !user.passwordHash) {
      throw new UnauthorizedException('Invalid credentials provided.');
    }

    const isMatch = await bcrypt.compare(dto.password, user.passwordHash);
    if (!isMatch) {
      throw new UnauthorizedException('Invalid credentials provided.');
    }

    if (
      user.accountStatus === AccountStatus.SUSPENDED ||
      user.accountStatus === AccountStatus.BLOCKED
    ) {
      throw new UnauthorizedException(
        'Your account has been restricted. Please contact support.',
      );
    }

    const displayName =
      user.displayName || (user.email ? user.email.split('@')[0] : 'Explorer');
    return this.createSessionAndTokens(user, displayName, ipAddress, userAgent);
  }

  async googleAuth(
    dto: GoogleAuthRequestDto,
    ipAddress?: string,
    userAgent?: string,
  ): Promise<AuthResponseDto> {
    if (!dto.idToken) {
      throw new BadRequestException('Google ID token is required');
    }

    const googleId = `google_${randomUUID().slice(0, 8)}`;
    const email = `google_user_${randomUUID().slice(0, 5)}@gmail.com`;
    const name = 'Google Explorer';

    let user = await this.authRepository.findByEmail(email);
    if (!user) {
      user = new UserAuthEntity({
        id: randomUUID(),
        email: email.toLowerCase(),
        googleId,
        role: UserRole.INDIVIDUAL,
        accountStatus: AccountStatus.PROFILE_INCOMPLETE,
        isEmailVerified: true,
        createdAt: new Date(),
        updatedAt: new Date(),
      });
      await this.authRepository.create(user);
    }

    return this.createSessionAndTokens(user, name, ipAddress, userAgent);
  }

  async refreshToken(
    dto: RefreshTokenRequestDto,
    ipAddress?: string,
    userAgent?: string,
  ): Promise<AuthResponseDto> {
    if (!dto.refreshToken) {
      throw new UnauthorizedException('Refresh token is missing');
    }

    let payload: any;
    try {
      payload = this.jwtService.verify(dto.refreshToken);
    } catch {
      throw new UnauthorizedException(
        'Invalid or expired refresh token session.',
      );
    }

    const userId = payload?.sub;
    const sessionId = payload?.sessionId;

    if (!userId || !sessionId) {
      throw new UnauthorizedException('Invalid refresh token payload.');
    }

    const user = await this.authRepository.findById(userId);
    if (!user) {
      throw new UnauthorizedException('User account not found.');
    }

    const session = await this.authRepository.findSessionById(sessionId);
    if (!session || session.isRevoked || session.userId !== userId) {
      throw new UnauthorizedException('Session has been revoked or expired.');
    }

    const accessToken = this.jwtService.sign({
      sub: user.id,
      sessionId: session.id,
      email: user.email,
      accountStatus: user.accountStatus,
      role: user.role,
    });

    const newRefreshToken = this.jwtService.sign(
      { sub: user.id, sessionId: session.id },
      { expiresIn: '7d' },
    );

    const refreshTokenHash = await bcrypt.hash(newRefreshToken, 8);

    session.refreshTokenHash = refreshTokenHash;
    session.expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000);
    session.lastActive = new Date();
    if (ipAddress) session.ipAddress = ipAddress;
    await this.authRepository.saveSession(session);

    const displayName =
      user.displayName || (user.email ? user.email.split('@')[0] : 'Explorer');

    const authUser: AuthUserDto = {
      id: user.id,
      email: user.email,
      name: displayName,
      role: user.role,
      accountStatus: user.accountStatus,
      isEmailVerified: user.isEmailVerified,
    };

    return {
      user: authUser,
      accessToken,
      refreshToken: newRefreshToken,
      expiresIn: 3600,
    };
  }

  async logout(userId: string, refreshToken?: string): Promise<void> {
    if (refreshToken) {
      try {
        const payload: any = this.jwtService.decode(refreshToken);
        if (payload?.sessionId) {
          await this.authRepository.deleteSessionByIdAndUser(
            payload.sessionId,
            userId,
          );
          return;
        }
      } catch {
        // Fallback to deleting all user sessions
      }
    }
    if (userId) {
      await this.authRepository.deleteAllUserSessions(userId);
    }
  }

  async revokeAllSessions(userId: string): Promise<void> {
    await this.authRepository.deleteAllUserSessions(userId);
  }

  async revokeOtherSessions(
    userId: string,
    currentSessionId: string,
  ): Promise<void> {
    await this.authRepository.deleteOtherUserSessions(userId, currentSessionId);
  }

  async getActiveSessions(userId: string): Promise<UserSessionEntity[]> {
    return this.authRepository.findActiveSessionsByUserId(userId);
  }

  async revokeSessionById(userId: string, sessionId: string): Promise<void> {
    const session = await this.authRepository.findSessionById(sessionId);
    if (session && session.userId === userId) {
      await this.authRepository.deleteSessionByIdAndUser(sessionId, userId);
    }
  }

  private extractDeviceMetadata(userAgent?: string, userId?: string) {
    if (!userAgent) {
      const fp = createHash('sha256')
        .update(`${userId || ''}:Desktop PC:Browser:Desktop`)
        .digest('hex')
        .slice(0, 16);
      return {
        deviceType: 'Desktop',
        operatingSystem: 'Desktop PC',
        browser: 'Browser',
        deviceInfo: 'Desktop PC • Browser',
        deviceFingerprint: fp,
      };
    }

    let os = 'Desktop PC';
    if (/windows nt 10/i.test(userAgent)) os = 'Windows PC';
    else if (/windows/i.test(userAgent)) os = 'Windows PC';
    else if (/macintosh|mac os x/i.test(userAgent)) os = 'MacBook Pro / Mac';
    else if (/iphone|ipad|ipod/i.test(userAgent)) os = 'iPhone';
    else if (/android/i.test(userAgent)) os = 'Android Device';
    else if (/linux/i.test(userAgent)) os = 'Linux PC';

    let browser = 'Browser';
    if (/chrome|crios/i.test(userAgent) && !/edg|opr/i.test(userAgent))
      browser = 'Chrome';
    else if (/safari/i.test(userAgent) && !/chrome|crios/i.test(userAgent))
      browser = 'Safari';
    else if (/firefox|fxios/i.test(userAgent)) browser = 'Firefox';
    else if (/edg/i.test(userAgent)) browser = 'Edge';
    else if (/opr/i.test(userAgent)) browser = 'Opera';

    let deviceType = 'Desktop';
    if (/mobile|iphone|ipod|android/i.test(userAgent)) deviceType = 'Mobile';
    else if (/ipad|tablet/i.test(userAgent)) deviceType = 'Tablet';

    const rawFp = `${userId || ''}:${os}:${browser}:${deviceType}`;
    const deviceFingerprint = createHash('sha256')
      .update(rawFp)
      .digest('hex')
      .slice(0, 16);

    return {
      deviceType,
      operatingSystem: os,
      browser,
      deviceInfo: `${os} • ${browser}`,
      deviceFingerprint,
    };
  }

  private async createSessionAndTokens(
    user: UserAuthEntity,
    name: string,
    ipAddress?: string,
    userAgent?: string,
  ): Promise<AuthResponseDto> {
    const meta = this.extractDeviceMetadata(userAgent, user.id);
    const resolvedIp =
      ipAddress === '::1' ? '127.0.0.1' : ipAddress || '127.0.0.1';

    // Enterprise session reuse: check if an active session exists for this device fingerprint
    let session = await this.authRepository.findActiveSessionByFingerprint(
      user.id,
      meta.deviceFingerprint,
    );
    let sessionId: string;

    if (session) {
      sessionId = session.id;
    } else {
      sessionId = randomUUID();
      // Enforce Enterprise Limit: Maximum 4 concurrent active sessions per user profile
      const activeSessions =
        await this.authRepository.findActiveSessionsByUserId(user.id);
      if (activeSessions.length >= 4) {
        const sorted = activeSessions.sort(
          (a, b) =>
            new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime(),
        );
        const numToDelete = activeSessions.length - 3;
        for (let i = 0; i < numToDelete; i++) {
          await this.authRepository.deleteSession(sorted[i].id);
        }
      }
    }

    const accessToken = this.jwtService.sign({
      sub: user.id,
      sessionId,
      email: user.email,
      accountStatus: user.accountStatus,
      role: user.role,
    });

    const refreshToken = this.jwtService.sign(
      { sub: user.id, sessionId },
      { expiresIn: '7d' },
    );

    const refreshTokenHash = await bcrypt.hash(refreshToken, 8);

    if (session) {
      session.refreshTokenHash = refreshTokenHash;
      session.ipAddress = resolvedIp;
      session.lastActive = new Date();
      session.expiresAt = new Date(Date.now() + 7 * 24 * 60 * 60 * 1000);
      await this.authRepository.saveSession(session);
    } else {
      session = new UserSessionEntity({
        id: sessionId,
        userId: user.id,
        refreshTokenHash,
        deviceInfo: meta.deviceInfo,
        deviceType: meta.deviceType,
        operatingSystem: meta.operatingSystem,
        browser: meta.browser,
        deviceFingerprint: meta.deviceFingerprint,
        ipAddress: resolvedIp,
        isRevoked: false,
        lastActive: new Date(),
        expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000),
        createdAt: new Date(),
      });
      await this.authRepository.createSession(session);
    }

    const authUser: AuthUserDto = {
      id: user.id,
      email: user.email,
      name,
      role: user.role,
      accountStatus: user.accountStatus,
      isEmailVerified: user.isEmailVerified,
    };

    return {
      user: authUser,
      accessToken,
      refreshToken,
      expiresIn: 3600,
    };
  }
}

import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
  OnGatewayInit,
  ConnectedSocket,
  MessageBody,
} from '@nestjs/websockets';
import { Server, Socket } from 'socket.io';
import { Injectable, Logger, Inject, forwardRef } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { ConfigService } from '@nestjs/config';
import { plainToInstance } from 'class-transformer';
import { validate } from 'class-validator';
import { ChatService } from './services/chat.service';
import { CommunityChatService } from './services/community-chat.service';
import { PresenceService } from './services/presence.service';
import { ChatEventDispatcher } from './services/chat-event.dispatcher';
import {
  CommunityEventDispatcher,
  CommunityEvents,
} from '../community/events/community-event.dispatcher';
import { ConversationRepository } from './repositories/conversation.repository';
import {
  SendMessageDto,
  MarkReadDto,
  MarkDeliveredDto,
  TypingDto,
  OpenConversationDto,
} from './dto/send-message.dto';
import { SOCKET_EVENTS } from './constants/chat.constants';
import {
  MessageCreatedEvent,
  MessageDeliveredEvent,
  MessageReadEvent,
  MessageEditedEvent,
  MessageDeletedEvent,
} from './interfaces/chat-event.interface';
import { PresenceStatus } from './interfaces/presence.interface';

/**
 * ChatGateway — Thin socket handler layer.
 *
 * Rules:
 * - Handlers only: authenticate → validate → call service → return ACK
 * - NO business logic, NO raw DB queries, NO repository calls
 * - All events return typed ACKs: { success, ...data } or { success: false, code, message }
 *
 * Delivery lifecycle managed here:
 * - After broadcasting message:new, the gateway immediately dispatches MESSAGE_DELIVERED
 *   for all recipients who are currently online (their socket exists in the room).
 *   This closes the SENT → DELIVERED gap when both users are online simultaneously.
 */
@Injectable()
@WebSocketGateway({
  cors: { origin: true, credentials: true },
  transports: ['websocket', 'polling'],
  path: '/socket.io/',
})
export class ChatGateway
  implements OnGatewayInit, OnGatewayConnection, OnGatewayDisconnect
{
  @WebSocketServer()
  server: Server;

  private readonly logger = new Logger(ChatGateway.name);

  constructor(
    private readonly jwtService: JwtService,
    private readonly configService: ConfigService,
    private readonly chatService: ChatService,
    private readonly communityChatService: CommunityChatService,
    private readonly presenceService: PresenceService,
    private readonly chatEventDispatcher: ChatEventDispatcher,
    @Inject(forwardRef(() => CommunityEventDispatcher))
    private readonly communityEventDispatcher: CommunityEventDispatcher,
    private readonly conversationRepository: ConversationRepository,
  ) {}

  afterInit(_server: Server): void {
    this.registerEventSubscribers();
  }

  // ─────────────────────────────────────────────────────────
  // CONNECTION LIFECYCLE
  // ─────────────────────────────────────────────────────────

  async handleConnection(socket: Socket): Promise<void> {
    const userId = await this.authenticateSocket(socket);

    if (!userId) {
      this.logger.warn(`Socket ${socket.id} rejected — invalid or missing JWT`);
      socket.emit(SOCKET_EVENTS.AUTH_ERROR, {
        message: 'Authentication required.',
      });
      socket.disconnect(true);
      return;
    }

    socket.data.userId = userId;
    this.presenceService.connect(userId, socket.id);
    await socket.join(`user:${userId}`);

    socket.emit(SOCKET_EVENTS.CONNECTED, {
      socketId: socket.id,
      userId,
      status: PresenceStatus.ONLINE,
    });

    // Notify only users who share a conversation with this user, not ALL sockets globally.
    // For now we broadcast to the server room for this user — presence is lightweight.
    this.server.to(`user:${userId}`).emit(SOCKET_EVENTS.PRESENCE_CHANGE, {
      userId,
      status: PresenceStatus.ONLINE,
    });

    this.chatEventDispatcher.dispatchUserConnected(userId, socket.id);
  }

  handleDisconnect(socket: Socket): void {
    const userId = socket.data.userId;
    if (!userId) return;

    this.presenceService.disconnect(userId, socket.id);
    const isStillOnline = this.presenceService.isOnline(userId);

    this.chatEventDispatcher.dispatchUserDisconnected(
      userId,
      socket.id,
      isStillOnline,
    );

    if (!isStillOnline) {
      const presence = this.presenceService.getPresence(userId);
      this.server.to(`user:${userId}`).emit(SOCKET_EVENTS.PRESENCE_CHANGE, {
        userId,
        status: PresenceStatus.OFFLINE,
        lastSeen: presence?.lastSeen,
      });
    }
  }

  // ─────────────────────────────────────────────────────────
  // SOCKET EVENT HANDLERS
  // ─────────────────────────────────────────────────────────

  @SubscribeMessage(SOCKET_EVENTS.SEND_MESSAGE)
  async handleSendMessage(
    @ConnectedSocket() socket: Socket,
    @MessageBody() rawData: Record<string, unknown>,
  ): Promise<Record<string, unknown>> {
    const userId = socket.data.userId;
    if (!userId) return this.ackError('AUTH_REQUIRED', 'Not authenticated.');

    const dto = plainToInstance(SendMessageDto, rawData);
    const errors = await validate(dto);
    if (errors.length > 0) {
      const detail = errors
        .map((e) => Object.values(e.constraints ?? {}).join(', '))
        .join('; ');
      this.logger.warn(
        `[SendMsg:Invalid] socketId=${socket.id} userId=${userId} errors=${detail}`,
      );
      return this.ackError('VALIDATION_ERROR', detail);
    }

    try {
      const message = await this.chatService.sendMessage(userId, dto);
      return {
        success: true,
        clientMessageId: dto.clientMessageId,
        serverMessageId: message.id,
        status: message.status,
        createdAt: message.createdAt,
      };
    } catch (error: any) {
      this.logger.error(
        `[SendMsg:Fail] socketId=${socket.id} error=${error.message}`,
      );
      return this.ackError(
        error.status === 429 ? 'RATE_LIMITED' : 'SEND_FAILED',
        error.message,
      );
    }
  }

  @SubscribeMessage(SOCKET_EVENTS.TYPING_START)
  handleTypingStart(
    @ConnectedSocket() socket: Socket,
    @MessageBody() data: TypingDto,
  ): Record<string, unknown> {
    const userId = socket.data.userId;
    if (!userId || !data?.conversationId) return { success: false };

    this.presenceService.startTyping(userId, data.conversationId);
    socket
      .to(`conv:${data.conversationId}`)
      .emit(SOCKET_EVENTS.TYPING_START_BROADCAST, {
        userId,
        conversationId: data.conversationId,
      });
    return { success: true };
  }

  @SubscribeMessage(SOCKET_EVENTS.TYPING_STOP)
  handleTypingStop(
    @ConnectedSocket() socket: Socket,
    @MessageBody() data: TypingDto,
  ): Record<string, unknown> {
    const userId = socket.data.userId;
    if (!userId || !data?.conversationId) return { success: false };

    this.presenceService.stopTyping(userId, data.conversationId);
    socket
      .to(`conv:${data.conversationId}`)
      .emit(SOCKET_EVENTS.TYPING_STOP_BROADCAST, {
        userId,
        conversationId: data.conversationId,
      });
    return { success: true };
  }

  @SubscribeMessage(SOCKET_EVENTS.MARK_DELIVERED)
  async handleMarkDelivered(
    @ConnectedSocket() socket: Socket,
    @MessageBody() data: MarkDeliveredDto,
  ): Promise<Record<string, unknown>> {
    const userId = socket.data.userId;
    if (!userId || !data?.messageId) return { success: false };
    try {
      await this.chatService.markDelivered(data.messageId, userId);
    } catch (_) {
      /* non-critical */
    }
    return { success: true };
  }

  @SubscribeMessage(SOCKET_EVENTS.MARK_READ)
  async handleMarkRead(
    @ConnectedSocket() socket: Socket,
    @MessageBody() data: MarkReadDto,
  ): Promise<Record<string, unknown>> {
    const userId = socket.data.userId;
    if (!userId || !data?.conversationId) return { success: false };
    try {
      if (data.messageId) {
        await this.chatService.markRead(
          userId,
          data.conversationId,
          data.messageId,
        );
      } else {
        await this.conversationRepository.clearUnreadCount(
          data.conversationId,
          userId,
        );
        this.server.to(`user:${userId}`).emit('conversation:updated', {
          conversationId: data.conversationId,
        });
      }
    } catch (_) {
      /* non-critical */
    }
    return { success: true };
  }

  @SubscribeMessage(SOCKET_EVENTS.OPEN_CONVERSATION)
  async handleOpenConversation(
    @ConnectedSocket() socket: Socket,
    @MessageBody() data: OpenConversationDto,
  ): Promise<Record<string, unknown>> {
    const userId = socket.data.userId;
    if (!userId || !data?.conversationId) {
      return this.ackError('VALIDATION_ERROR', 'conversationId required.');
    }

    try {
      // 1. Join the socket room so receiver gets future messages in real-time
      await socket.join(`conv:${data.conversationId}`);

      // 2. Clear unread count and update lastReadAt
      await this.conversationRepository.clearUnreadCount(
        data.conversationId,
        userId,
      );

      // Notify the user's sockets to update conversation list (e.g. unread count to 0)
      this.server
        .to(`user:${userId}`)
        .emit('conversation:updated', { conversationId: data.conversationId });

      // 3. Bulk-deliver any SENT messages the user hasn't received yet
      await this.chatService.markConversationDelivered(
        data.conversationId,
        userId,
      );

      // 4. Load recent history
      const { items } = await this.chatService.getMessages(
        userId,
        data.conversationId,
        30,
      );

      return {
        success: true,
        conversationId: data.conversationId,
        messages: items,
      };
    } catch (error: any) {
      this.logger.error(
        `[OpenConv:Fail] convId=${data.conversationId} userId=${userId} error=${error.message}`,
      );
      return this.ackError('OPEN_FAILED', error.message);
    }
  }

  // ─────────────────────────────────────────────────────────
  // COMMUNITY CHAT EVENT HANDLERS
  // ─────────────────────────────────────────────────────────

  @SubscribeMessage('join_community')
  async handleJoinCommunity(
    @ConnectedSocket() socket: Socket,
    @MessageBody() data: { communityId: string },
  ): Promise<Record<string, unknown>> {
    const userId = socket.data.userId;
    if (!userId || !data?.communityId)
      return this.ackError('VALIDATION_ERROR', 'communityId required.');

    try {
      await socket.join(`room:community:${data.communityId}`);
      await socket.join(`community:${data.communityId}`);
      return { success: true };
    } catch (error: any) {
      return this.ackError('JOIN_FAILED', error.message);
    }
  }

  @SubscribeMessage('leave_community')
  async handleLeaveCommunity(
    @ConnectedSocket() socket: Socket,
    @MessageBody() data: { communityId: string },
  ): Promise<Record<string, unknown>> {
    const userId = socket.data.userId;
    if (!userId || !data?.communityId)
      return this.ackError('VALIDATION_ERROR', 'communityId required.');

    try {
      await socket.leave(`room:community:${data.communityId}`);
      await socket.leave(`community:${data.communityId}`);
      return { success: true };
    } catch (error: any) {
      return this.ackError('LEAVE_FAILED', error.message);
    }
  }

  @SubscribeMessage('community:send_message')
  async handleCommunitySendMessage(
    @ConnectedSocket() socket: Socket,
    @MessageBody() rawData: Record<string, unknown>,
  ): Promise<unknown> {
    const userId = socket.data.userId;
    if (!userId) return this.ackError('AUTH_REQUIRED', 'Not authenticated.');
    if (!rawData.communityId)
      return this.ackError('VALIDATION_ERROR', 'communityId required.');

    const dto = plainToInstance(SendMessageDto, rawData);
    const errors = await validate(dto);
    if (errors.length > 0) {
      const detail = errors
        .map((e) => Object.values(e.constraints ?? {}).join(', '))
        .join('; ');
      this.logger.error(
        `[CommSendMsg:ValidationFail] socketId=${socket.id} error=${detail} rawData=${JSON.stringify(rawData)}`,
      );
      return this.ackError('VALIDATION_ERROR', detail);
    }

    try {
      const message = await this.communityChatService.sendMessage(
        userId,
        rawData.communityId as string,
        dto,
      );
      return message;
    } catch (error: any) {
      this.logger.error(
        `[CommSendMsg:Fail] socketId=${socket.id} error=${error.message}`,
      );
      return this.ackError(
        error.status === 429 ? 'RATE_LIMITED' : 'SEND_FAILED',
        error.message,
      );
    }
  }

  @SubscribeMessage('community:join-lobby')
  async handleJoinLobby(
    @ConnectedSocket() socket: Socket,
    @MessageBody() data: { communityId: string; user: Record<string, unknown> },
  ): Promise<Record<string, unknown>> {
    const userId = socket.data.userId;
    if (!userId || !data?.communityId) return { success: false };
    await socket.join(`community:${data.communityId}`);
    await socket.join(`room:community:${data.communityId}`);
    this.chatEventDispatcher.dispatch({
      type: 'COMMUNITY_JOIN_LOBBY' as any,
      payload: {
        communityId: data.communityId,
        userId,
        user: data.user,
        socketId: socket.id,
      },
    });
    return { success: true };
  }

  @SubscribeMessage('community:leave-lobby')
  async handleLeaveLobby(
    @ConnectedSocket() socket: Socket,
    @MessageBody() data: { communityId: string },
  ): Promise<Record<string, unknown>> {
    const userId = socket.data.userId;
    if (!userId || !data?.communityId) return { success: false };
    await socket.leave(`community:${data.communityId}`);
    await socket.leave(`room:community:${data.communityId}`);
    this.chatEventDispatcher.dispatch({
      type: 'COMMUNITY_LEAVE_LOBBY' as any,
      payload: { communityId: data.communityId, userId, socketId: socket.id },
    });
    return { success: true };
  }

  // ─────────────────────────────────────────────────────────
  // EVENT SUBSCRIBERS
  // ─────────────────────────────────────────────────────────

  private registerEventSubscribers(): void {
    /**
     * MESSAGE_CREATED
     *
     * Broadcast message to all participants via their private `user:{id}` room.
     * Using `user:` rooms (not `conv:`) ensures multi-device delivery —
     * every tab and device for a user receives the message even if they haven't
     * called open-conversation.
     *
     * Delivery lifecycle:
     * - Emit message:new to each recipient
     * - If the recipient is ONLINE (socket exists), immediately dispatch MESSAGE_DELIVERED
     *   server-side. This transitions status SENT → DELIVERED without requiring the
     *   client to explicitly emit mark-delivered.
     */
    this.chatEventDispatcher.subscribe<MessageCreatedEvent>(
      'MESSAGE_CREATED',
      async (payload) => {
        const { message, recipientIds } = payload;

        for (const recipientId of recipientIds) {
          // Emit message:new to all devices of this participant
          this.server
            .to(`user:${recipientId}`)
            .emit(SOCKET_EVENTS.MESSAGE_NEW, {
              message: this.chatService.toResponseDto(message),
              conversationId: message.conversationId,
            });

          // Auto-deliver for RECIPIENTS (not the sender) who are online right now
          if (
            recipientId !== message.senderId &&
            this.presenceService.isOnline(recipientId)
          ) {
            try {
              await this.chatService.markDelivered(message.id, recipientId);
            } catch (_) {
              /* non-critical — status stays SENT if this fails */
            }
          }
        }
      },
    );

    /** MESSAGE_DELIVERED → notify the sender their message was received */
    this.chatEventDispatcher.subscribe<MessageDeliveredEvent>(
      'MESSAGE_DELIVERED',
      (payload) => {
        this.server
          .to(`user:${payload.senderId}`)
          .emit(SOCKET_EVENTS.MESSAGE_DELIVERED, {
            messageId: payload.messageId,
            conversationId: payload.conversationId,
            deliveredAt: payload.deliveredAt,
          });
      },
    );

    /** MESSAGE_READ → notify the sender their message was read */
    this.chatEventDispatcher.subscribe<MessageReadEvent>(
      'MESSAGE_READ',
      (payload) => {
        this.server
          .to(`user:${payload.senderId}`)
          .emit(SOCKET_EVENTS.MESSAGE_READ, {
            messageId: payload.messageId,
            conversationId: payload.conversationId,
            readAt: payload.readAt,
          });
      },
    );

    /** MESSAGE_EDITED → broadcast to all sockets in the conversation room */
    this.chatEventDispatcher.subscribe<MessageEditedEvent>(
      'MESSAGE_EDITED',
      (payload) => {
        this.server
          .to(`conv:${payload.conversationId}`)
          .emit(SOCKET_EVENTS.MESSAGE_EDITED, payload);
      },
    );

    /** MESSAGE_DELETED → broadcast to all sockets in the conversation room */
    this.chatEventDispatcher.subscribe<MessageDeletedEvent>(
      'MESSAGE_DELETED',
      (payload) => {
        this.server
          .to(`conv:${payload.conversationId}`)
          .emit(SOCKET_EVENTS.MESSAGE_DELETED, payload);
      },
    );

    /** COMMUNITY_MESSAGE_CREATED → broadcast to all sockets in the community room */
    this.chatEventDispatcher.subscribe<any>(
      'COMMUNITY_MESSAGE_CREATED',
      (payload) => {
        const { communityId, message } = payload;
        this.server
          .to(`room:community:${communityId}`)
          .to(`community:${communityId}`)
          .emit(SOCKET_EVENTS.MESSAGE_NEW, {
            message,
            conversationId: message.conversationId,
            communityId,
          });
      },
    );

    this.communityEventDispatcher.on(
      CommunityEvents.MEMBER_MUTED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:moderation:action', { ...payload, action: 'MUTE' });
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.MEMBER_UNMUTED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:moderation:action', {
            ...payload,
            action: 'UNMUTE',
          });
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.MEMBER_BANNED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:moderation:action', { ...payload, action: 'BAN' });
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.MEMBER_UNBANNED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:moderation:action', { ...payload, action: 'UNBAN' });
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.MEMBER_WARNED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:moderation:action', { ...payload, action: 'WARN' });
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.MEMBER_KICKED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:moderation:action', { ...payload, action: 'KICK' });
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.ROLE_CHANGED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:role:updated', payload);
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.SETTINGS_UPDATED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:settings:updated', payload);
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.JOINED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:member:joined', payload);
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.LEFT,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:member:left', payload);
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.OWNER_TRANSFERRED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:ownership:transferred', payload);
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
    this.communityEventDispatcher.on(
      CommunityEvents.UPDATED,
      (payload: Record<string, unknown>) => {
        this.server
          .to(`room:community:${payload.communityId}`)
          .to(`community:${payload.communityId}`)
          .emit('community:updated', payload);
        this.server.emit('COMMUNITY_UPDATED', {
          communityId: payload.communityId,
        });
      },
    );
  }

  // ─────────────────────────────────────────────────────────
  // PRIVATE HELPERS
  // ─────────────────────────────────────────────────────────

  private async authenticateSocket(socket: Socket): Promise<string | null> {
    try {
      const token =
        socket.handshake.auth?.token ||
        socket.handshake.headers?.authorization?.replace('Bearer ', '') ||
        (socket.handshake.query?.token as string);

      if (!token) return null;

      const secret = this.configService.get<string>(
        'jwt.secret',
        'wandercall_jwt_secret_key_2026',
      );
      const payload = this.jwtService.verify<{ sub: string; email: string }>(
        token,
        { secret },
      );
      return payload.sub ?? null;
    } catch {
      return null;
    }
  }

  private ackError(code: string, message: string) {
    return { success: false, code, message };
  }
}

import {
  Controller,
  Get,
  Post,
  Delete,
  Patch,
  Param,
  Query,
  Body,
  UseGuards,
  ParseIntPipe,
  DefaultValuePipe,
  HttpCode,
  HttpStatus,
  createParamDecorator,
  ExecutionContext,
} from '@nestjs/common';
import { JwtAuthGuard } from '../../auth/guards/jwt-auth.guard';
import { ChatService } from '../services/chat.service';
import { PresenceService } from '../services/presence.service';
import { SendMessageDto } from '../dto/send-message.dto';
import { plainToInstance } from 'class-transformer';
import { RequestWithUser } from '../../../core/interfaces/request-with-user.interface';

// ─────────────────────────────────────────────────────────
// Decorator — extract authenticated user from request
// ─────────────────────────────────────────────────────────
interface AuthUser {
  userId: string;
  email: string;
  role: string;
  accountStatus: string;
}

export const GetUser = createParamDecorator(
  (_data: unknown, ctx: ExecutionContext): AuthUser => {
    const request = ctx.switchToHttp().getRequest<RequestWithUser>();
    return request.user as unknown as AuthUser;
  },
);

/**
 * ChatController — HTTP REST endpoints for chat.
 *
 * Covers operations that are HTTP by nature:
 * - Fetching conversation list (page load)
 * - Fetching message history (pagination / initial load)
 * - Getting or creating a direct conversation (before socket connect)
 * - Deleting / editing a message
 *
 * Real-time operations (send, typing, read receipts) go through the Socket gateway.
 */
import { CommunityChatService } from '../services/community-chat.service';

@UseGuards(JwtAuthGuard)
@Controller('chat')
export class ChatController {
  constructor(
    private readonly chatService: ChatService,
    private readonly presenceService: PresenceService,
    private readonly communityChatService: CommunityChatService,
  ) {}

  /**
   * GET /api/v1/chat/communities/:communityId/conversations/:conversationId/messages
   * Fetch messages for a community chat (validates via CommunityMemberEntity instead of ConversationParticipantEntity).
   */
  @Get('communities/:communityId/conversations/:conversationId/messages')
  async getCommunityMessages(
    @GetUser() user: AuthUser,
    @Param('communityId') communityId: string,
    @Param('conversationId') conversationId: string,
    @Query('limit', new DefaultValuePipe(30), ParseIntPipe) limit: number,
    @Query('cursor') cursor?: string,
  ) {
    const dateCursor =
      cursor && cursor.trim() !== '' && cursor !== 'undefined'
        ? new Date(cursor)
        : undefined;
    return this.communityChatService.getMessages(
      user.userId,
      communityId,
      conversationId,
      dateCursor,
      limit,
    );
  }

  /**
   * GET /api/v1/chat/communities/:communityId/default-conversation
   * Gets the default base conversation for a community
   */
  @Get('communities/:communityId/default-conversation')
  async getCommunityDefaultConversation(
    @Param('communityId') communityId: string,
  ) {
    return this.communityChatService.getDefaultConversation(communityId);
  }

  @Post('conversations/:conversationId/messages')
  async sendMessage(
    @GetUser() user: AuthUser,
    @Param('conversationId') conversationId: string,
    @Body()
    body: {
      clientMessageId: string;
      type?: string;
      text?: string;
      attachments?: any[];
      replyToId?: string;
      metadata?: Record<string, any>;
    },
  ) {
    const dto = plainToInstance(SendMessageDto, {
      clientMessageId: body.clientMessageId,
      conversationId,
      type: body.type,
      text: body.text,
      attachments: body.attachments,
      replyToId: body.replyToId,
      metadata: body.metadata,
    });
    return this.chatService.sendMessage(user.userId, dto);
  }

  /**
   * GET /api/v1/chat/conversations
   * Returns all conversations for the authenticated user.
   */
  @Get('conversations')
  async getConversations(@GetUser() user: AuthUser) {
    return this.chatService.getConversations(user.userId);
  }

  /**
   * POST /api/v1/chat/conversations/direct/:targetUserId
   * Get or create a direct conversation with a user.
   */
  @Post('conversations/direct/:targetUserId')
  async getOrCreateDirect(
    @GetUser() user: AuthUser,
    @Param('targetUserId') targetUserId: string,
  ) {
    return this.chatService.getOrCreateDirectConversation(
      user.userId,
      targetUserId,
    );
  }

  /**
   * GET /api/v1/chat/conversations/:conversationId/messages
   * Cursor-based message history.
   */
  @Get('conversations/:conversationId/messages')
  async getMessages(
    @GetUser() user: AuthUser,
    @Param('conversationId') conversationId: string,
    @Query('limit', new DefaultValuePipe(30), ParseIntPipe) limit: number,
    @Query('cursor') cursor?: string,
  ) {
    return this.chatService.getMessages(
      user.userId,
      conversationId,
      limit,
      cursor,
    );
  }

  /**
   * PATCH /api/v1/chat/messages/:messageId
   * Edit a message.
   */
  @Patch('messages/:messageId')
  async editMessage(
    @GetUser() user: AuthUser,
    @Param('messageId') messageId: string,
    @Body('text') text: string,
  ) {
    return this.chatService.editMessage(user.userId, messageId, text);
  }

  /**
   * DELETE /api/v1/chat/messages/:messageId
   * Soft-delete a message.
   */
  @Delete('messages/:messageId')
  @HttpCode(HttpStatus.NO_CONTENT)
  async deleteMessage(
    @GetUser() user: AuthUser,
    @Param('messageId') messageId: string,
  ) {
    return this.chatService.deleteMessage(user.userId, messageId);
  }

  /**
   * GET /api/v1/chat/presence/:userId
   * Check whether a user is currently online.
   */
  @Get('presence/:userId')
  async getPresence(@Param('userId') userId: string) {
    const presence = this.presenceService.getPresence(userId);
    return {
      userId,
      isOnline: this.presenceService.isOnline(userId),
      status: presence?.status ?? 'OFFLINE',
      lastSeen: presence?.lastSeen,
    };
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { DataSource, Repository } from 'typeorm';
import { randomUUID } from 'crypto';
import {
  ConversationEntity,
  ConversationType,
} from '../entities/conversation.entity';
import { ConversationParticipantEntity } from '../entities/conversation-participant.entity';

@Injectable()
export class ConversationRepository {
  private readonly logger = new Logger(ConversationRepository.name);

  constructor(
    @InjectRepository(ConversationEntity)
    private readonly convRepo: Repository<ConversationEntity>,
    @InjectRepository(ConversationParticipantEntity)
    private readonly participantRepo: Repository<ConversationParticipantEntity>,
    private readonly dataSource: DataSource,
  ) {}

  /**
   * Find or create a DIRECT conversation between exactly two users.
   *
   * Architecture:
   * - Uses `participantKey` column (format: "sortedIdA:sortedIdB") as the unique identity
   * - Single INSERT ... ON CONFLICT (participantKey) DO NOTHING + SELECT is fully atomic
   * - No separate check-then-create needed — the unique constraint handles races at DB level
   * - Advisory lock fallback retained for extra safety on concurrent inserts
   *
   * This guarantees: for any pair of users, exactly ONE conversation ever exists.
   */
  async findOrCreateDirect(
    userAId: string,
    userBId: string,
  ): Promise<ConversationEntity> {
    // Canonical sorted key — always the same regardless of argument order
    const [idA, idB] = [userAId, userBId].sort();
    const participantKey = `${idA}:${idB}`;

    // Fast path: lookup by participantKey (indexed, O(1))
    const existing = await this.convRepo.findOne({
      where: { participantKey, type: ConversationType.DIRECT },
    });

    if (existing) {
      return existing;
    }

    // Slow path with advisory lock to serialize concurrent first-time creates
    const lockKey1 = this.hashUserId(idA);
    const lockKey2 = this.hashUserId(idB);

    return this.dataSource.transaction(async (manager) => {
      // Acquire transaction-level advisory lock — released when transaction ends
      await manager.query(`SELECT pg_advisory_xact_lock($1, $2)`, [
        lockKey1,
        lockKey2,
      ]);

      // Re-check inside the lock (another transaction may have just committed)
      const doubleCheck = await manager.findOne(ConversationEntity, {
        where: { participantKey, type: ConversationType.DIRECT },
      });

      if (doubleCheck) {
        return doubleCheck;
      }

      // Create
      const conversation = manager.create(ConversationEntity, {
        id: randomUUID(),
        type: ConversationType.DIRECT,
        participantKey,
        unreadCounts: {},
      });
      const savedConv = await manager.save(ConversationEntity, conversation);

      const participantA = manager.create(ConversationParticipantEntity, {
        conversationId: savedConv.id,
        userId: idA,
        joinedAt: new Date(),
      });
      const participantB = manager.create(ConversationParticipantEntity, {
        conversationId: savedConv.id,
        userId: idB,
        joinedAt: new Date(),
      });
      await manager.save(ConversationParticipantEntity, [
        participantA,
        participantB,
      ]);

      this.logger.log(
        `Created DIRECT conversation ${savedConv.id} (key: ${participantKey})`,
      );
      return savedConv;
    });
  }

  /**
   * Derive a stable int32 from a UUID string for use as advisory lock key.
   */
  private hashUserId(userId: string): number {
    const hex = userId.replace(/-/g, '');
    let hash = 0;
    for (let i = 0; i < hex.length; i += 8) {
      hash ^= parseInt(hex.slice(i, i + 8), 16) | 0;
    }
    return hash;
  }

  async findById(id: string): Promise<ConversationEntity | null> {
    return this.convRepo.findOne({ where: { id } });
  }

  /**
   * Get all conversations for a user, ordered by last message time.
   * Returns a lightweight list suitable for the conversation sidebar.
   */
  async findByUserId(userId: string): Promise<ConversationEntity[]> {
    return this.dataSource
      .createQueryBuilder(ConversationEntity, 'c')
      .innerJoin(
        ConversationParticipantEntity,
        'p',
        'p.conversationId = c.id AND p.userId = :userId AND p.hasLeft = false',
        { userId },
      )
      .orderBy('c.lastMessageAt', 'DESC', 'NULLS LAST')
      .addOrderBy('c.createdAt', 'DESC')
      .getMany();
  }

  /**
   * Get participants for a conversation.
   */
  async getParticipants(
    conversationId: string,
  ): Promise<ConversationParticipantEntity[]> {
    return this.participantRepo.find({ where: { conversationId } });
  }

  /**
   * Check if a user is a participant in a conversation.
   */
  async isParticipant(
    conversationId: string,
    userId: string,
  ): Promise<boolean> {
    const count = await this.participantRepo.count({
      where: { conversationId, userId, hasLeft: false },
    });
    return count > 0;
  }

  /**
   * Get the participant record — used for updating lastReadAt.
   */
  async getParticipant(
    conversationId: string,
    userId: string,
  ): Promise<ConversationParticipantEntity | null> {
    return this.participantRepo.findOne({ where: { conversationId, userId } });
  }

  /**
   * Update the lastMessage summary on a conversation after a new message is sent.
   * Called by ChatService after persisting a message.
   */
  async updateLastMessage(
    conversationId: string,
    messageId: string,
    senderId: string,
    text: string,
    sentAt: Date,
    recipientIds: string[],
  ): Promise<void> {
    const conversation = await this.convRepo.findOneOrFail({
      where: { id: conversationId },
    });

    const updatePayload: any = {
      lastMessageId: messageId,
      lastMessageSenderId: senderId,
      lastMessageText: text.length > 100 ? text.slice(0, 100) + '…' : text,
      lastMessageAt: sentAt,
    };

    // ONLY update JSONB unreadCounts for direct/group conversations to avoid massive row locks.
    if (
      conversation.type !== ConversationType.COMMUNITY &&
      conversation.type !== ConversationType.CAMPFIRE
    ) {
      const updatedUnreadCounts = { ...conversation.unreadCounts };
      for (const recipientId of recipientIds) {
        if (recipientId !== senderId) {
          updatedUnreadCounts[recipientId] =
            (updatedUnreadCounts[recipientId] || 0) + 1;
        }
      }
      updatePayload.unreadCounts = updatedUnreadCounts;
    }

    await this.convRepo.update(conversationId, updatePayload);
  }

  /**
   * Clear the unread count for a user in a conversation.
   * Called when the user opens the conversation.
   */
  async clearUnreadCount(
    conversationId: string,
    userId: string,
  ): Promise<void> {
    const conversation = await this.convRepo.findOne({
      where: { id: conversationId },
    });
    if (!conversation) return;

    const updatedCounts = { ...conversation.unreadCounts };
    updatedCounts[userId] = 0;
    await this.convRepo.update(conversationId, { unreadCounts: updatedCounts });

    // Update participant's lastReadAt
    await this.participantRepo.update(
      { conversationId, userId },
      { lastReadAt: new Date() },
    );
  }

  /**
   * Get the IDs of all participants in a conversation.
   */
  async getParticipantIds(conversationId: string): Promise<string[]> {
    const participants = await this.participantRepo.find({
      where: { conversationId },
    });
    return participants.map((p) => p.userId);
  }

  async createCommunityConversation(
    communityId: string,
  ): Promise<ConversationEntity> {
    const conversation = this.convRepo.create({
      id: randomUUID(),
      type: ConversationType.COMMUNITY,
      metadata: {
        communityId,
        isDefault: true,
      },
      createdAt: new Date(),
      updatedAt: new Date(),
    });
    return this.convRepo.save(conversation);
  }

  async findDefaultCommunityConversation(
    communityId: string,
  ): Promise<ConversationEntity | null> {
    return this.convRepo
      .createQueryBuilder('conv')
      .where('conv.type = :type', { type: ConversationType.COMMUNITY })
      .andWhere("conv.metadata->>'communityId' = :communityId", { communityId })
      .andWhere("conv.metadata->>'isDefault' = 'true'")
      .getOne();
  }

  async createCampfireConversation(
    campfireId: string,
  ): Promise<ConversationEntity> {
    const conversation = this.convRepo.create({
      id: randomUUID(),
      type: ConversationType.CAMPFIRE,
      metadata: { campfireId },
      createdAt: new Date(),
      updatedAt: new Date(),
    });
    return this.convRepo.save(conversation);
  }

  async findCampfireConversation(
    campfireId: string,
  ): Promise<ConversationEntity | null> {
    return this.convRepo
      .createQueryBuilder('conv')
      .where('conv.type = :type', { type: ConversationType.CAMPFIRE })
      .andWhere("conv.metadata->>'campfireId' = :campfireId", { campfireId })
      .getOne();
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository, LessThan, IsNull } from 'typeorm';
import { MessageEntity, MessageStatus } from '../entities/message.entity';
import {
  DEFAULT_MESSAGE_PAGE_SIZE,
  MAX_MESSAGE_PAGE_SIZE,
} from '../constants/chat.constants';

export interface PaginatedMessages {
  items: MessageEntity[];
  nextCursor?: string;
  hasMore: boolean;
}

@Injectable()
export class MessageRepository {
  private readonly logger = new Logger(MessageRepository.name);

  constructor(
    @InjectRepository(MessageEntity)
    private readonly messageRepo: Repository<MessageEntity>,
  ) {}

  /**
   * Persist a new message to the database.
   */
  async save(message: MessageEntity): Promise<MessageEntity> {
    return this.messageRepo.save(message);
  }

  /**
   * Find a message by its server-assigned ID.
   */
  async findById(id: string): Promise<MessageEntity | null> {
    return this.messageRepo.findOne({ where: { id } });
  }

  /**
   * Find a message by the client-generated UUID.
   * Used for idempotency — prevents duplicate messages on client retry.
   */
  async findByClientMessageId(
    clientMessageId: string,
  ): Promise<MessageEntity | null> {
    return this.messageRepo.findOne({ where: { clientMessageId } });
  }

  /**
   * Cursor-based pagination for conversation message history.
   * Fetches messages BEFORE the cursor (older messages).
   * Ordered newest-first within the cursor window, then reversed for display.
   */
  async paginate(
    conversationId: string,
    limit: number = DEFAULT_MESSAGE_PAGE_SIZE,
    cursor?: string,
  ): Promise<PaginatedMessages> {
    const safeLimit = Math.min(limit, MAX_MESSAGE_PAGE_SIZE);

    const qb = this.messageRepo
      .createQueryBuilder('msg')
      .where('msg.conversationId = :conversationId', { conversationId })
      .andWhere('msg.isDeleted = :isDeleted', { isDeleted: false })
      .orderBy('msg.createdAt', 'DESC')
      .take(safeLimit + 1);

    if (cursor) {
      qb.andWhere('msg.createdAt < :cursor', { cursor: new Date(cursor) });
    }

    const raw = await qb.getMany();
    const hasMore = raw.length > safeLimit;
    if (hasMore) raw.pop();

    const nextCursor =
      hasMore && raw.length > 0
        ? raw[raw.length - 1].createdAt.toISOString()
        : undefined;

    // Reverse so oldest is first (chronological display order)
    return { items: raw.reverse(), nextCursor, hasMore };
  }

  /**
   * Get unread messages in a conversation for a user since their lastReadAt.
   */
  async findUnread(
    conversationId: string,
    userId: string,
    since?: Date,
  ): Promise<MessageEntity[]> {
    const qb = this.messageRepo
      .createQueryBuilder('msg')
      .where('msg.conversationId = :conversationId', { conversationId })
      .andWhere('msg.senderId != :userId', { userId })
      .andWhere('msg.isDeleted = false')
      .andWhere('msg.status != :status', { status: MessageStatus.READ })
      .orderBy('msg.createdAt', 'ASC');

    if (since) {
      qb.andWhere('msg.createdAt > :since', { since });
    }

    return qb.getMany();
  }

  /**
   * Mark a single message as delivered.
   * Returns the updated message or null if not found.
   */
  async markDelivered(messageId: string): Promise<MessageEntity | null> {
    const message = await this.findById(messageId);
    if (!message || message.status === MessageStatus.READ) return null;

    message.status = MessageStatus.DELIVERED;
    message.deliveredAt = new Date();
    return this.messageRepo.save(message);
  }

  /**
   * Mark all undelivered messages in a conversation as delivered for a user.
   * Called when user reconnects — delivers all pending messages in bulk.
   */
  async markAllDelivered(
    conversationId: string,
    recipientId: string,
  ): Promise<void> {
    await this.messageRepo
      .createQueryBuilder()
      .update(MessageEntity)
      .set({ status: MessageStatus.DELIVERED, deliveredAt: new Date() })
      .where('conversationId = :conversationId', { conversationId })
      .andWhere('senderId != :recipientId', { recipientId })
      .andWhere('status = :status', { status: MessageStatus.SENT })
      .andWhere('isDeleted = false')
      .execute();
  }

  /**
   * Mark a message as read.
   */
  async markRead(messageId: string): Promise<MessageEntity | null> {
    const message = await this.findById(messageId);
    if (!message) return null;

    message.status = MessageStatus.READ;
    message.readAt = new Date();
    return this.messageRepo.save(message);
  }

  /**
   * Soft-edit a message's text.
   */
  async edit(
    messageId: string,
    newText: string,
  ): Promise<MessageEntity | null> {
    const message = await this.findById(messageId);
    if (!message || message.isDeleted) return null;

    message.text = newText;
    message.isEdited = true;
    message.status = MessageStatus.EDITED;
    return this.messageRepo.save(message);
  }

  /**
   * Soft-delete a message.
   */
  async softDelete(messageId: string): Promise<MessageEntity | null> {
    const message = await this.findById(messageId);
    if (!message) return null;

    message.isDeleted = true;
    message.deletedAt = new Date();
    message.status = MessageStatus.DELETED;
    message.text = undefined;
    message.attachments = undefined;
    return this.messageRepo.save(message);
  }

  /**
   * Search messages by text in a conversation.
   */
  async search(
    conversationId: string,
    query: string,
    limit = 20,
  ): Promise<MessageEntity[]> {
    return this.messageRepo
      .createQueryBuilder('msg')
      .where('msg.conversationId = :conversationId', { conversationId })
      .andWhere('msg.isDeleted = false')
      .andWhere('msg.text ILIKE :query', { query: `%${query}%` })
      .orderBy('msg.createdAt', 'DESC')
      .take(limit)
      .getMany();
  }
}

import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { EventEmitter } from 'events';
import {
  ChatEvent,
  IChatEventDispatcher,
} from '../interfaces/chat-event.interface';
import { RedisService } from '../../redis/redis-core.service';
import { MessageEntity } from '../entities/message.entity';

@Injectable()
export class ChatEventDispatcher
  extends EventEmitter
  implements IChatEventDispatcher, OnModuleInit
{
  private readonly logger = new Logger(ChatEventDispatcher.name);

  constructor(private readonly redisService: RedisService) {
    super();
    this.setMaxListeners(50);
  }

  onModuleInit() {
    this.initializeRedisSubscriber();
  }

  private initializeRedisSubscriber() {
    const subscriber = this.redisService.subscriber;
    // Subscribe to all community events using pattern
    subscriber.psubscribe('community:*:events', (err, count) => {
      if (err) {
        this.logger.error(
          'Failed to subscribe to Redis community events pattern',
          err,
        );
      } else {
      }
    });

    subscriber.on('pmessage', (pattern, channel, message) => {
      try {
        const payload = JSON.parse(message);
        // Forward the Redis event to our local in-process EventEmitter
        // so that the local Gateway can emit it to connected sockets on THIS node.
        if (payload.type === 'COMMUNITY_MESSAGE_CREATED') {
          this.emit('COMMUNITY_MESSAGE_CREATED', payload.data);
        }
      } catch (err) {
        this.logger.error('Failed to parse Redis pub/sub message', err);
      }
    });
  }

  dispatch<T extends ChatEvent>(event: T): void {
    this.emit(event.type, event.payload);
    this.emit('*', event);
  }

  subscribe<T extends ChatEvent>(
    eventType: T['type'],
    handler: (payload: T['payload']) => void,
  ): void {
    this.on(eventType, handler);
  }

  dispatchUserConnected(userId: string, socketId: string) {
    this.dispatch({
      type: 'USER_CONNECTED',
      payload: { userId, socketId },
    });
  }

  dispatchUserDisconnected(
    userId: string,
    socketId: string,
    isStillOnline: boolean,
  ) {
    this.dispatch({
      type: 'USER_DISCONNECTED',
      payload: { userId, socketId, isStillOnline },
    });
  }

  /**
   * Dispatches a community message.
   * Instead of just emitting locally, this publishes to Redis so ALL gateway nodes receive it.
   */
  dispatchCommunityMessage(communityId: string, message: MessageEntity) {
    const payload = {
      type: 'COMMUNITY_MESSAGE_CREATED',
      data: { communityId, message },
    };

    // Publish to Redis
    this.redisService.client
      .publish(`community:${communityId}:events`, JSON.stringify(payload))
      .catch((err) => {
        this.logger.error(
          `Failed to publish community message to Redis: ${err.message}`,
        );
      });
  }
}

import {
  BadRequestException,
  ForbiddenException,
  HttpException,
  HttpStatus,
  Injectable,
  Logger,
  NotFoundException,
} from '@nestjs/common';
import { InjectDataSource } from '@nestjs/typeorm';
import { DataSource } from 'typeorm';
import { randomUUID } from 'crypto';
import {
  MessageEntity,
  MessageStatus,
  MessageType,
} from '../entities/message.entity';
import { ConversationEntity } from '../entities/conversation.entity';
import { MessageRepository } from '../repositories/message.repository';
import { ConversationRepository } from '../repositories/conversation.repository';
import { ChatEventDispatcher } from './chat-event.dispatcher';
import { PrivacyService } from '../../privacy/services/privacy.service';
import { UserRepository } from '../../user/repositories/user.repository';
import { SendMessageDto } from '../dto/send-message.dto';
import { MessageResponseDto } from '../dto/conversation-response.dto';
import {
  MAX_MESSAGE_LENGTH,
  RATE_LIMIT_MAX_MESSAGES,
  RATE_LIMIT_WINDOW_MS,
} from '../constants/chat.constants';

/**
 * ChatService — Core business logic layer.
 *
 * Responsibilities:
 * - Conversation lifecycle (create / resolve / list)
 * - Message lifecycle (send / edit / delete / deliver / read)
 * - Rate limiting
 * - Event dispatching
 *
 * Rules:
 * - Never emits socket events — delegates to ChatEventDispatcher
 * - Never contains Socket.IO references
 * - All multi-step DB operations run inside transactions
 */
@Injectable()
export class ChatService {
  private readonly logger = new Logger(ChatService.name);

  /** In-memory rate limiter — future: replace with Redis INCR+EXPIRE */
  private readonly rateLimitMap = new Map<
    string,
    { count: number; windowStart: number }
  >();

  constructor(
    private readonly messageRepository: MessageRepository,
    private readonly conversationRepository: ConversationRepository,
    private readonly chatEventDispatcher: ChatEventDispatcher,
    private readonly privacyService: PrivacyService,
    private readonly userRepository: UserRepository,
    @InjectDataSource()
    private readonly dataSource: DataSource,
  ) {}

  // ─────────────────────────────────────────────────────────
  // CONVERSATION MANAGEMENT
  // ─────────────────────────────────────────────────────────

  async getOrCreateDirectConversation(
    requesterId: string,
    targetUserId: string,
  ): Promise<{ conversationId: string }> {
    if (requesterId === targetUserId) {
      throw new BadRequestException(
        'Cannot start a conversation with yourself.',
      );
    }

    const [requesterBlocked, targetBlocked] = await Promise.all([
      this.privacyService.checkIsBlocked(requesterId, targetUserId),
      this.privacyService.checkIsBlocked(targetUserId, requesterId),
    ]);

    if (requesterBlocked || targetBlocked) {
      throw new ForbiddenException(
        'Cannot start a conversation with this user.',
      );
    }

    const conversation = await this.conversationRepository.findOrCreateDirect(
      requesterId,
      targetUserId,
    );

    return { conversationId: conversation.id };
  }

  async getConversations(userId: string) {
    const conversations =
      await this.conversationRepository.findByUserId(userId);
    return conversations.map((conv) => ({
      ...conv,
      unreadCount: conv.unreadCounts[userId] ?? 0,
    }));
  }

  // ─────────────────────────────────────────────────────────
  // MESSAGE SENDING — atomic transaction
  // ─────────────────────────────────────────────────────────

  /**
   * Full send pipeline:
   * 1. Rate limit
   * 2. Membership check
   * 3. Privacy (block) check
   * 4. Content validation
   * 5. Idempotency (clientMessageId)
   * 6. Persist message + update conversation summary — ONE transaction
   * 7. Dispatch MESSAGE_CREATED
   */
  async sendMessage(
    senderId: string,
    dto: SendMessageDto,
  ): Promise<MessageResponseDto> {
    // 1. Rate limiting
    this.enforceRateLimit(senderId);

    // 2. Membership check
    const isMember = await this.conversationRepository.isParticipant(
      dto.conversationId,
      senderId,
    );
    if (!isMember) {
      throw new ForbiddenException(
        'You are not a participant in this conversation.',
      );
    }

    // 3. Privacy check
    const recipientIds = await this.conversationRepository.getParticipantIds(
      dto.conversationId,
    );
    const otherParticipants = recipientIds.filter((id) => id !== senderId);

    for (const recipientId of otherParticipants) {
      const [blockedBySender, blockedByRecipient] = await Promise.all([
        this.privacyService.checkIsBlocked(senderId, recipientId),
        this.privacyService.checkIsBlocked(recipientId, senderId),
      ]);
      if (blockedBySender || blockedByRecipient) {
        throw new ForbiddenException(
          'Message cannot be sent due to privacy settings.',
        );
      }
    }

    // 4. Content validation
    if (!dto.text && (!dto.attachments || dto.attachments.length === 0)) {
      if (dto.type === MessageType.TEXT || !dto.type) {
        throw new BadRequestException('Message must have text or attachments.');
      }
    }
    if (dto.text && dto.text.length > MAX_MESSAGE_LENGTH) {
      throw new BadRequestException(
        `Message exceeds maximum length of ${MAX_MESSAGE_LENGTH} characters.`,
      );
    }

    // 5. Idempotency
    const existing = await this.messageRepository.findByClientMessageId(
      dto.clientMessageId,
    );
    if (existing) {
      this.logger.warn(
        `[Idempotent] clientMessageId=${dto.clientMessageId} already exists — returning cached`,
      );
      return this.toResponseDto(existing);
    }

    // 6. Persist message + update conversation summary inside ONE transaction
    const saved = await this.dataSource.transaction(async (manager) => {
      const message = manager.create(MessageEntity, {
        id: randomUUID(),
        clientMessageId: dto.clientMessageId,
        conversationId: dto.conversationId,
        senderId,
        type: dto.type ?? MessageType.TEXT,
        text: dto.text,
        attachments: dto.attachments,
        replyToId: dto.replyToId,
        metadata: dto.metadata,
        status: MessageStatus.SENT,
        mentions: [],
        reactions: {},
      });

      const savedMsg = await manager.save(MessageEntity, message);

      // Update lastMessage summary and increment unread for each recipient
      // Unread is ONLY incremented for users who do NOT have the conversation actively open.
      // "Actively open" is approximated by lastReadAt being recent — the client sends
      // mark-read on open-conversation, which updates lastReadAt.
      const conversation = await manager.findOneOrFail(ConversationEntity, {
        where: { id: dto.conversationId },
      });

      const updatedUnreadCounts = { ...conversation.unreadCounts };
      for (const recipientId of recipientIds) {
        if (recipientId !== senderId) {
          // Only increment if recipient hasn't explicitly cleared unread recently.
          // We do increment here — the client clears it on open-conversation.
          updatedUnreadCounts[recipientId] =
            (updatedUnreadCounts[recipientId] ?? 0) + 1;
        }
      }

      const previewText = dto.text
        ? dto.text.length > 100
          ? dto.text.slice(0, 100) + '…'
          : dto.text
        : `[${dto.type ?? 'attachment'}]`;

      await manager.update(ConversationEntity, dto.conversationId, {
        lastMessageId: savedMsg.id,
        lastMessageSenderId: senderId,
        lastMessageText: previewText,
        lastMessageAt: savedMsg.createdAt,
        unreadCounts: updatedUnreadCounts,
      });

      return savedMsg;
    });

    // 7. Dispatch — gateway picks this up and broadcasts
    const conversation = await this.conversationRepository.findById(
      dto.conversationId,
    );
    this.chatEventDispatcher.dispatch({
      type: 'MESSAGE_CREATED',
      payload: {
        message: saved,
        conversation: conversation!,
        recipientIds,
      },
    });

    return this.toResponseDto(saved);
  }

  // ─────────────────────────────────────────────────────────
  // MESSAGE HISTORY
  // ─────────────────────────────────────────────────────────

  async getMessages(
    userId: string,
    conversationId: string,
    limit: number,
    cursor?: string,
  ) {
    const isMember = await this.conversationRepository.isParticipant(
      conversationId,
      userId,
    );
    if (!isMember) {
      throw new ForbiddenException(
        'You are not a participant in this conversation.',
      );
    }
    return this.messageRepository.paginate(conversationId, limit, cursor);
  }

  // ─────────────────────────────────────────────────────────
  // DELIVERY PIPELINE
  // ─────────────────────────────────────────────────────────

  /**
   * Mark a single message as DELIVERED and notify the sender.
   * Called by the gateway immediately after broadcasting message:new to the receiver.
   */
  async markDelivered(messageId: string, recipientId: string): Promise<void> {
    const updated = await this.messageRepository.markDelivered(messageId);
    if (!updated) return;

    this.chatEventDispatcher.dispatch({
      type: 'MESSAGE_DELIVERED',
      payload: {
        messageId,
        conversationId: updated.conversationId,
        senderId: updated.senderId,
        deliveredAt: updated.deliveredAt!,
      },
    });
  }

  /**
   * Mark ALL SENT messages in a conversation as DELIVERED for a connecting user.
   * Called on open-conversation to catch up messages sent while user was offline.
   */
  async markConversationDelivered(
    conversationId: string,
    recipientId: string,
  ): Promise<void> {
    const messages = await this.messageRepository.findUnread(
      conversationId,
      recipientId,
    );
    const sentMessages = messages.filter(
      (m) => m.status === MessageStatus.SENT,
    );

    for (const msg of sentMessages) {
      const updated = await this.messageRepository.markDelivered(msg.id);
      if (!updated) continue;

      this.chatEventDispatcher.dispatch({
        type: 'MESSAGE_DELIVERED',
        payload: {
          messageId: msg.id,
          conversationId: msg.conversationId,
          senderId: msg.senderId,
          deliveredAt: updated.deliveredAt!,
        },
      });
    }
  }

  /**
   * Mark a message as READ and clear unread count for this conversation.
   * Called when user has the conversation open.
   */
  async markRead(
    userId: string,
    conversationId: string,
    messageId: string,
  ): Promise<void> {
    const isMember = await this.conversationRepository.isParticipant(
      conversationId,
      userId,
    );
    if (!isMember) throw new ForbiddenException('Not a participant.');

    // Always clear unread count when user is looking at the conversation
    await this.conversationRepository.clearUnreadCount(conversationId, userId);

    if (!messageId) return;

    const targetMessage = await this.messageRepository.findById(messageId);
    if (!targetMessage) return;

    const unreadMessages = await this.messageRepository.findUnread(
      conversationId,
      userId,
    );
    const toRead = unreadMessages.filter(
      (m) => m.createdAt.getTime() <= targetMessage.createdAt.getTime(),
    );

    for (const msg of toRead) {
      const updated = await this.messageRepository.markRead(msg.id);
      if (!updated) continue;

      this.chatEventDispatcher.dispatch({
        type: 'MESSAGE_READ',
        payload: {
          messageId: msg.id,
          conversationId,
          senderId: updated.senderId,
          readerId: userId,
          readAt: updated.readAt!,
        },
      });
    }
  }

  // ─────────────────────────────────────────────────────────
  // EDIT & DELETE
  // ─────────────────────────────────────────────────────────

  async editMessage(
    userId: string,
    messageId: string,
    newText: string,
  ): Promise<MessageResponseDto> {
    const message = await this.messageRepository.findById(messageId);
    if (!message) throw new NotFoundException('Message not found.');
    if (message.senderId !== userId)
      throw new ForbiddenException('You can only edit your own messages.');
    if (!newText || newText.length > MAX_MESSAGE_LENGTH) {
      throw new BadRequestException('Invalid message text.');
    }

    const updated = await this.messageRepository.edit(messageId, newText);
    if (!updated)
      throw new NotFoundException('Message not found or already deleted.');

    this.chatEventDispatcher.dispatch({
      type: 'MESSAGE_EDITED',
      payload: {
        messageId,
        conversationId: updated.conversationId,
        newText,
        editedAt: updated.updatedAt,
      },
    });

    return this.toResponseDto(updated);
  }

  async deleteMessage(userId: string, messageId: string): Promise<void> {
    const message = await this.messageRepository.findById(messageId);
    if (!message) throw new NotFoundException('Message not found.');
    if (message.senderId !== userId)
      throw new ForbiddenException('You can only delete your own messages.');

    await this.messageRepository.softDelete(messageId);

    this.chatEventDispatcher.dispatch({
      type: 'MESSAGE_DELETED',
      payload: {
        messageId,
        conversationId: message.conversationId,
        deletedBy: userId,
        deletedAt: new Date(),
      },
    });
  }

  // ─────────────────────────────────────────────────────────
  // HELPERS
  // ─────────────────────────────────────────────────────────

  private enforceRateLimit(userId: string): void {
    const now = Date.now();
    const entry = this.rateLimitMap.get(userId);

    if (!entry || now - entry.windowStart > RATE_LIMIT_WINDOW_MS) {
      this.rateLimitMap.set(userId, { count: 1, windowStart: now });
      return;
    }

    entry.count += 1;
    if (entry.count > RATE_LIMIT_MAX_MESSAGES) {
      throw new HttpException(
        `Rate limit exceeded. Max ${RATE_LIMIT_MAX_MESSAGES} messages per ${RATE_LIMIT_WINDOW_MS / 1000}s.`,
        HttpStatus.TOO_MANY_REQUESTS,
      );
    }
  }

  toResponseDto(message: MessageEntity): MessageResponseDto {
    return {
      id: message.id,
      clientMessageId: message.clientMessageId,
      conversationId: message.conversationId,
      senderId: message.senderId,
      type: message.type,
      text: message.text,
      attachments: message.attachments,
      replyToId: message.replyToId,
      status: message.status,
      isEdited: message.isEdited,
      isDeleted: message.isDeleted,
      reactions: message.reactions,
      deliveredAt: message.deliveredAt,
      readAt: message.readAt,
      metadata: message.metadata,
      createdAt: message.createdAt,
      updatedAt: message.updatedAt,
    };
  }
}

import {
  BadRequestException,
  ForbiddenException,
  Injectable,
  Logger,
} from '@nestjs/common';
import { InjectDataSource } from '@nestjs/typeorm';
import { DataSource } from 'typeorm';
import { randomUUID } from 'crypto';
import {
  MessageEntity,
  MessageType,
  MessageStatus,
} from '../entities/message.entity';
import {
  ConversationEntity,
  ConversationType,
} from '../entities/conversation.entity';
import { MessageRepository } from '../repositories/message.repository';
import { ConversationRepository } from '../repositories/conversation.repository';
import { ChatEventDispatcher } from './chat-event.dispatcher';
import { SendMessageDto } from '../dto/send-message.dto';
import { SendMessageAckDto } from '../dto/conversation-response.dto';
import { CommunityMemberRepository } from '../../community/repositories/community-member.repository';
import { CommunityMemberStatus } from '../../community/entities/community-member.entity';
import { MAX_MESSAGE_LENGTH } from '../constants/chat.constants';
import { MessageService } from './message.service';

@Injectable()
export class CommunityChatService {
  private readonly logger = new Logger(CommunityChatService.name);
  private readonly rateLimitMap = new Map<
    string,
    { count: number; windowStart: number }
  >();

  constructor(
    private readonly messageRepository: MessageRepository,
    private readonly conversationRepository: ConversationRepository,
    private readonly communityMemberRepo: CommunityMemberRepository,
    private readonly chatEventDispatcher: ChatEventDispatcher,
    private readonly messageService: MessageService,
    @InjectDataSource()
    private readonly dataSource: DataSource,
  ) {}

  private enforceRateLimit(userId: string): void {
    const now = Date.now();
    const windowMs = 5000;
    const maxMessages = 10;

    let record = this.rateLimitMap.get(userId);
    if (!record || now - record.windowStart > windowMs) {
      record = { count: 0, windowStart: now };
    }

    record.count++;
    this.rateLimitMap.set(userId, record);

    if (record.count > maxMessages) {
      throw new BadRequestException(
        'Rate limit exceeded. Please wait before sending more messages.',
      );
    }
  }

  async sendMessage(
    senderId: string,
    communityId: string,
    dto: SendMessageDto,
  ): Promise<SendMessageAckDto> {
    this.enforceRateLimit(senderId);

    const member = await this.communityMemberRepo.findByUserAndCommunity(
      senderId,
      communityId,
    );
    if (!member || member.status !== CommunityMemberStatus.ACTIVE) {
      throw new ForbiddenException(
        'You must be an active member of this community to send messages.',
      );
    }
    if (member.isMuted) {
      throw new ForbiddenException(
        'You are currently muted in this community.',
      );
    }

    await this.messageService.validateMessageContent(dto);

    const conversationId = dto.conversationId;

    // In the future, check CommunityRoom settings here (e.g., slowMode, announcementOnly)

    const { message: sentMessage, isDuplicate } =
      await this.messageService.persistMessage(
        senderId,
        conversationId,
        dto,
        [], // Community messages don't lock per-user unread counts in the DB
      );

    if (!isDuplicate) {
      // Enforce 500 messages cap efficiently in the background
      this.dataSource
        .query(
          `
        DELETE FROM chat_messages 
        WHERE id IN (
          SELECT id FROM chat_messages 
          WHERE "conversationId" = $1 
          ORDER BY "createdAt" DESC 
          OFFSET 500
        )
      `,
          [conversationId],
        )
        .catch((err) => {
          this.logger.error(
            `Failed to enforce message cap for community conversation ${conversationId}`,
            err,
          );
        });

      this.chatEventDispatcher.dispatchCommunityMessage(
        communityId,
        sentMessage,
      );
    }

    return {
      success: true,
      clientMessageId: dto.clientMessageId,
      serverMessageId: sentMessage.id,
      status: sentMessage.status,
      createdAt: sentMessage.createdAt,
    };
  }

  async getMessages(
    userId: string,
    communityId: string,
    conversationId: string,
    cursor?: Date,
    limit = 50,
  ) {
    const member = await this.communityMemberRepo.findByUserAndCommunity(
      userId,
      communityId,
    );
    if (!member || member.status !== CommunityMemberStatus.ACTIVE) {
      throw new ForbiddenException('Not an active member of this community.');
    }

    return this.messageRepository.paginate(
      conversationId,
      limit,
      cursor?.toISOString(),
    );
  }

  async createBaseConversation(communityId: string, ownerId: string) {
    return this.conversationRepository.createCommunityConversation(communityId);
  }

  async getDefaultConversation(
    communityId: string,
  ): Promise<ConversationEntity> {
    let conv =
      await this.conversationRepository.findDefaultCommunityConversation(
        communityId,
      );
    if (!conv) {
      this.logger.warn(
        `Default conversation not found for community ${communityId}. Auto-provisioning...`,
      );
      conv =
        await this.conversationRepository.createCommunityConversation(
          communityId,
        );
    }
    return conv;
  }
}

import { Injectable, Logger, BadRequestException } from '@nestjs/common';
import { MessageRepository } from '../repositories/message.repository';
import { ConversationRepository } from '../repositories/conversation.repository';
import { SendMessageDto } from '../dto/send-message.dto';
import {
  MessageEntity,
  MessageType,
  MessageStatus,
} from '../entities/message.entity';
import { randomUUID } from 'crypto';
import { InjectDataSource } from '@nestjs/typeorm';
import { DataSource } from 'typeorm';
import { MAX_MESSAGE_LENGTH } from '../constants/chat.constants';
import { SendMessageAckDto } from '../dto/conversation-response.dto';

@Injectable()
export class MessageService {
  private readonly logger = new Logger(MessageService.name);

  constructor(
    private readonly messageRepository: MessageRepository,
    private readonly conversationRepository: ConversationRepository,
    @InjectDataSource()
    private readonly dataSource: DataSource,
  ) {}

  async validateMessageContent(dto: SendMessageDto) {
    if (!dto.text && (!dto.attachments || dto.attachments.length === 0)) {
      if (dto.type === MessageType.TEXT || !dto.type) {
        throw new BadRequestException('Message must have text or attachments.');
      }
    }
    if (dto.text && dto.text.length > MAX_MESSAGE_LENGTH) {
      throw new BadRequestException(
        `Message exceeds maximum length of ${MAX_MESSAGE_LENGTH} characters.`,
      );
    }
  }

  async persistMessage(
    senderId: string,
    conversationId: string,
    dto: SendMessageDto,
    recipientIds: string[],
  ): Promise<{ message: MessageEntity; isDuplicate: boolean }> {
    const existing = await this.messageRepository.findByClientMessageId(
      dto.clientMessageId,
    );
    if (existing) {
      this.logger.warn(
        `Idempotency hit: Duplicate clientMessageId ${dto.clientMessageId}`,
      );
      return { message: existing, isDuplicate: true };
    }

    const sentMessage = await this.dataSource.transaction(async (manager) => {
      // 1. Generate next sequence number (using Postgres sequence or max query for simplicity in this iteration)
      const res = await manager.query(
        `SELECT COALESCE(MAX("sequenceNumber"), 0) + 1 AS next_seq FROM chat_messages WHERE "conversationId" = $1`,
        [conversationId],
      );
      const nextSequenceNumber = parseInt(res[0].next_seq, 10);

      const message = manager.create(MessageEntity, {
        id: randomUUID(),
        clientMessageId: dto.clientMessageId,
        conversationId,
        senderId,
        text: dto.text,
        type: dto.type || MessageType.TEXT,
        attachments: dto.attachments,
        replyToId: dto.replyToId,
        status: MessageStatus.SENT,
        sequenceNumber: nextSequenceNumber,
        createdAt: new Date(),
        updatedAt: new Date(),
        metadata: dto.metadata,
      });

      const savedMessage = await manager.save(MessageEntity, message);

      // 2. Update conversation summary
      await this.conversationRepository.updateLastMessage(
        conversationId,
        savedMessage.id,
        senderId,
        savedMessage.text || 'Attachment',
        savedMessage.createdAt,
        recipientIds,
      );

      return savedMessage;
    });

    return { message: sentMessage, isDuplicate: false };
  }
}

