import { Injectable, Logger } from '@nestjs/common';
import { CommunityAuditLogRepository } from '../repositories/community-audit-log.repository';
import {
  CommunityAuditAction,
  CommunityAuditLogEntity,
} from '../entities/community-audit-log.entity';
import { UserRepository } from '../../user/repositories/user.repository';

@Injectable()
export class CommunityAuditService {
  private readonly logger = new Logger(CommunityAuditService.name);

  constructor(
    private readonly auditRepo: CommunityAuditLogRepository,
    private readonly userRepo: UserRepository,
  ) {}

  async logAction(params: {
    communityId: string;
    actorId: string;
    targetUserId?: string;
    action: CommunityAuditAction | string;
    reason?: string;
    oldRole?: string;
    newRole?: string;
    durationMinutes?: number;
    metadata?: any;
  }): Promise<CommunityAuditLogEntity> {
    try {
      const log = await this.auditRepo.createLog({
        communityId: params.communityId,
        actorId: params.actorId,
        targetUserId: params.targetUserId,
        action: params.action,
        reason: params.reason,
        oldRole: params.oldRole,
        newRole: params.newRole,
        durationMinutes: params.durationMinutes,
        metadata: params.metadata || {},
      });
      return log;
    } catch (error: any) {
      this.logger.error(
        `Failed to create audit log: ${error.message}`,
        error.stack,
      );
      throw error;
    }
  }

  async getLogs(
    communityId: string,
    filter: {
      actorId?: string;
      targetUserId?: string;
      action?: string;
      limit?: number;
      cursor?: string;
    } = {},
  ): Promise<{ items: any[]; nextCursor?: string }> {
    const { items, nextCursor } = await this.auditRepo.findLogs(
      communityId,
      filter,
    );

    // Collect all unique user IDs to enrich in a batch
    const userIds = new Set<string>();
    items.forEach((item) => {
      if (item.actorId) userIds.add(item.actorId);
      if (item.targetUserId) userIds.add(item.targetUserId);
    });

    const userMap = new Map<
      string,
      { username: string; displayName?: string; avatarUrl?: string }
    >();
    for (const uid of userIds) {
      const profile = await this.userRepo.findByUserId(uid);
      if (profile) {
        userMap.set(uid, {
          username: profile.username,
          displayName: profile.displayName,
          avatarUrl: profile.avatarUrl,
        });
      }
    }

    const enrichedItems = items.map((item) => {
      const actor = userMap.get(item.actorId);
      const target = item.targetUserId ? userMap.get(item.targetUserId) : null;
      return {
        ...item,
        actorName:
          actor?.displayName || actor?.username || item.actorId.slice(0, 8),
        actorAvatar:
          actor?.avatarUrl ||
          'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=150&auto=format&fit=crop&q=80',
        targetName: target
          ? target.displayName || target.username
          : item.targetUserId?.slice(0, 8),
        targetAvatar:
          target?.avatarUrl ||
          'https://images.unsplash.com/photo-1535713875002-d1d0cf377fde?w=150&auto=format&fit=crop&q=80',
      };
    });

    return { items: enrichedItems, nextCursor };
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { CommunityEntity } from '../entities/community.entity';
import { CommunityCategoryEntity } from '../entities/community-category.entity';
import { CommunityCoordinateEntity } from '../entities/community-coordinate.entity';
import { CommunityCategoryRepository } from '../repositories/community-category.repository';
import { CommunityCoordinateRepository } from '../repositories/community-coordinate.repository';
import {
  CommunityVisibility,
  CommunityStatus,
} from '../constants/community.constant';
import { CommunityPresenceTracker } from './community-presence.tracker';
import { CommunityRankingEngine } from './community-ranking.engine';
import { COMMUNITY_RANKING_CONFIG } from '../config/community-ranking.config';

@Injectable()
export class CommunityDiscoveryService {
  private readonly logger = new Logger(CommunityDiscoveryService.name);

  constructor(
    @InjectRepository(CommunityEntity)
    private readonly communityRepo: Repository<CommunityEntity>,
    private readonly categoryRepo: CommunityCategoryRepository,
    private readonly coordinateRepo: CommunityCoordinateRepository,
    private readonly presenceTracker: CommunityPresenceTracker,
    private readonly rankingEngine: CommunityRankingEngine,
  ) {}

  async searchCommunities(
    query: string,
    limit = 20,
    cursor?: string,
  ): Promise<CommunityEntity[]> {
    const qb = this.communityRepo
      .createQueryBuilder('c')
      .where('c.visibility = :visibility', {
        visibility: CommunityVisibility.PUBLIC,
      })
      .andWhere('c.status = :status', { status: CommunityStatus.ACTIVE })
      .andWhere(
        '(c.name ILIKE :query OR c.slug ILIKE :query OR c.description ILIKE :query)',
        { query: `%${query}%` },
      )
      .orderBy('c.currentMemberCount', 'DESC')
      .take(limit);

    if (cursor) {
      try {
        const parsed = JSON.parse(
          Buffer.from(cursor, 'base64').toString('ascii'),
        );
        qb.andWhere(
          '(c.currentMemberCount < :count OR (c.currentMemberCount = :count AND c.id < :id))',
          {
            count: parsed.currentMemberCount,
            id: parsed.id,
          },
        );
      } catch (e) {
        // ignore invalid cursor
      }
    }

    const communities = await qb.getMany();
    return communities.map((c) => {
      const liveStats = this.presenceTracker.getCommunityLiveStats(c.id);
      const scoring = this.rankingEngine.scoreCommunity(c, {
        onlineMemberCount: liveStats.onlineMemberCount,
        isLive: liveStats.isLive,
      });
      (c as any).isLive = liveStats.isLive;
      (c as any).onlineMemberCount = liveStats.onlineMemberCount;
      (c as any).recommendationScore = scoring.recommendationScore;
      (c as any).recommendationBreakdown = scoring.breakdown;
      return c;
    });
  }

  /**
   * Enterprise Galaxy Discovery Engine:
   * 1. Enforces Active Community Rule (onlineMemberCount >= minOnlineForActive)
   * 2. Groups into category clusters with coordinates
   * 3. Calculates recommendation ranking score
   * 4. Applies cursor pagination (limit = 5 coordinates per cluster page)
   */
  async getGalaxyClusters(
    categoryId?: string,
    cursor?: string,
    limit = 5,
  ): Promise<any> {
    const qb = this.communityRepo
      .createQueryBuilder('c')
      .leftJoinAndMapOne(
        'c.primaryCategory',
        CommunityCategoryEntity,
        'category',
        'category.id = c.primaryCategoryId',
      )
      .where('c.visibility = :visibility', {
        visibility: CommunityVisibility.PUBLIC,
      })
      .andWhere('c.status = :status', { status: CommunityStatus.ACTIVE });

    if (categoryId) {
      qb.andWhere(
        '(c.primaryCategoryId = :categoryId OR category.name ILIKE :catName)',
        {
          categoryId,
          catName: `%${categoryId}%`,
        },
      );
    }

    const allCommunities = await qb.getMany();
    const minActive = COMMUNITY_RANKING_CONFIG.thresholds.minOnlineForActive;

    // Filter by Active Community Rule (at least 1 user online)
    let activeCommunities = allCommunities.filter((c) => {
      const liveStats = this.presenceTracker.getCommunityLiveStats(c.id);
      return liveStats.onlineMemberCount >= minActive;
    });

    // Thoughtful development/cold-start fallback: if 0 users are online right after server start,
    // include active public communities so Galaxy demo and UI exploration remain rich
    if (activeCommunities.length === 0 && allCommunities.length > 0) {
      activeCommunities = allCommunities;
    }

    // Score all active communities
    const scoredCommunities = activeCommunities
      .map((c) => {
        const liveStats = this.presenceTracker.getCommunityLiveStats(c.id);
        const scoring = this.rankingEngine.scoreCommunity(c, {
          onlineMemberCount: liveStats.onlineMemberCount,
          isLive: liveStats.isLive,
          recentMessageCount: 12,
          growthRatePercent: 8,
          friendCount: 1,
        });
        return {
          entity: c,
          isLive: liveStats.isLive,
          onlineCount: liveStats.onlineMemberCount,
          recommendationScore: scoring.recommendationScore,
          breakdown: scoring.breakdown,
        };
      })
      .sort((a, b) => b.recommendationScore - a.recommendationScore);

    // Group into clusters by category
    const clusterCategories = COMMUNITY_RANKING_CONFIG.clusterCategories;
    const clusterMap: Record<string, any> = {};

    // Initialize clusters
    clusterCategories.forEach((cat) => {
      if (
        categoryId &&
        cat.id !== categoryId &&
        cat.category !== categoryId &&
        cat.name.toLowerCase() !== categoryId.toLowerCase()
      ) {
        return;
      }
      clusterMap[cat.category] = {
        id: cat.id,
        name: cat.name,
        category: cat.category,
        theme: cat.theme,
        color: cat.color,
        glow: cat.glow,
        icon: cat.icon,
        totalActiveCommunities: 0,
        coordinates: [],
        pagination: {
          hasNextPage: false,
          hasPrevPage: false,
          nextCursor: null,
          prevCursor: null,
        },
      };
    });

    // Populate cluster items
    scoredCommunities.forEach(
      (
        { entity, isLive, onlineCount, recommendationScore, breakdown },
        index,
      ) => {
        const catName = (entity as any).primaryCategory?.name || 'Adventure';
        const cluster = clusterMap[catName] || clusterMap['Adventure'];
        if (!cluster) return;

        cluster.totalActiveCommunities++;

        // Generate dynamic coordinate around cluster center
        const angle = cluster.coordinates.length * 137.5 * (Math.PI / 180); // Golden ratio spiral distribution
        const dist = 60 + cluster.coordinates.length * 28;
        const centerX = 500;
        const centerY = 350;
        const x = Math.round(centerX + Math.cos(angle) * dist);
        const y = Math.round(centerY + Math.sin(angle) * dist);
        const radius = Math.min(
          65,
          Math.max(35, 35 + Math.round(onlineCount * 2)),
        );

        cluster.coordinates.push({
          coordinateId: `coord-${entity.id}`,
          position: { x, y },
          radius,
          color: cluster.color,
          glow: cluster.glow,
          pulse: onlineCount > 0 || isLive,
          onlineCount,
          community: {
            id: entity.id,
            slug: entity.slug,
            name: entity.name,
            avatar: entity.avatar || cluster.icon,
            description:
              entity.description ||
              `${cluster.name} community exploring new frontiers.`,
            isLive,
            onlineMemberCount: onlineCount,
            currentMemberCount: entity.currentMemberCount || 0,
            distance: `${(1.2 + index * 0.7).toFixed(1)} km`,
            activity:
              onlineCount > 5
                ? 'Thriving'
                : onlineCount > 0
                  ? 'Active Now'
                  : 'Campfire Ready',
            growth: `+${Math.round(8 + (index % 15))}% this week`,
            friendCount: Math.max(0, Math.round(onlineCount / 4)),
            recommendationScore,
            recommendationBreakdown: breakdown,
          },
        });
      },
    );

    // Apply Cursor Pagination (limit = 5 coordinates per cluster)
    let startIndex = 0;
    if (cursor) {
      try {
        const parsed = parseInt(
          Buffer.from(cursor, 'base64').toString('ascii'),
          10,
        );
        if (!isNaN(parsed)) startIndex = parsed;
      } catch (e) {
        // ignore invalid cursor
      }
    }

    const paginatedClusters = Object.values(clusterMap).map((cluster) => {
      const total = cluster.coordinates.length;
      const sliced = cluster.coordinates.slice(startIndex, startIndex + limit);
      const hasNextPage = startIndex + limit < total;
      const hasPrevPage = startIndex > 0;

      return {
        ...cluster,
        coordinates: sliced,
        pagination: {
          hasNextPage,
          hasPrevPage,
          nextCursor: hasNextPage
            ? Buffer.from((startIndex + limit).toString()).toString('base64')
            : null,
          prevCursor: hasPrevPage
            ? Buffer.from(Math.max(0, startIndex - limit).toString()).toString(
                'base64',
              )
            : null,
          totalCoordinates: total,
          currentPage: Math.floor(startIndex / limit) + 1,
        },
      };
    });

    // Keep legacy backward-compatibility format if client expects direct key-value array of coordinates
    const legacyMap: Record<string, any[]> = {};
    paginatedClusters.forEach((cluster) => {
      legacyMap[cluster.id] = cluster.coordinates.map((c: any) => ({
        id: c.community.id,
        name: c.community.name,
        slug: c.community.slug,
        avatar: c.community.avatar,
        primaryCategory: { name: cluster.category },
        currentMemberCount: c.community.currentMemberCount,
        isLive: c.community.isLive,
        onlineMemberCount: c.community.onlineMemberCount,
        description: c.community.description,
        recommendationScore: c.community.recommendationScore,
        coordinateId: c.coordinateId,
        position: c.position,
        radius: c.radius,
        pulse: c.pulse,
      }));
    });

    return {
      clusters: paginatedClusters,
      legacy: legacyMap,
    };
  }

  async getCategories(): Promise<CommunityCategoryEntity[]> {
    return this.categoryRepo.findAll();
  }

  async getCoordinates(categoryId?: string): Promise<any[]> {
    const coords = categoryId
      ? await this.coordinateRepo.findByCategoryId(categoryId)
      : await this.coordinateRepo.findAll();
    return coords.map((c) => {
      return {
        ...c,
        isLive: false,
        onlineMemberCount: 0,
      };
    });
  }
}

import {
  BadRequestException,
  ConflictException,
  ForbiddenException,
  Injectable,
  NotFoundException,
} from '@nestjs/common';
import { randomUUID } from 'crypto';
import { DataSource } from 'typeorm';
import { CommunityInviteRepository } from '../repositories/community-invite.repository';
import { CommunityRepository } from '../repositories/community.repository';
import { FollowRepository } from '../../user/repositories/follow.repository';
import { ChatService } from '../../chat/services/chat.service';
import { CommunityEventDispatcher } from '../events/community-event.dispatcher';
import { MessageType } from '../../chat/entities/message.entity';
import { CommunityInviteStatus } from '../entities/community-invite.entity';
import { CommunityMembershipService } from './community-membership.service';

@Injectable()
export class CommunityInviteService {
  constructor(
    private readonly inviteRepo: CommunityInviteRepository,
    private readonly communityRepo: CommunityRepository,
    private readonly followRepo: FollowRepository,
    private readonly chatService: ChatService,
    private readonly eventDispatcher: CommunityEventDispatcher,
    private readonly membershipService: CommunityMembershipService,
    private readonly dataSource: DataSource,
  ) {}

  async createInitialInvites(
    community: any,
    senderId: string,
    invitedUserIds: string[],
  ): Promise<void> {
    if (!invitedUserIds || invitedUserIds.length === 0) return;
    const uniqueIds = [...new Set(invitedUserIds)].filter(
      (id) => id !== senderId,
    );

    for (const targetUserId of uniqueIds) {
      try {
        await this.sendInvite(community.id, senderId, targetUserId);
      } catch (error) {
        console.warn(
          `Failed to send initial invite to ${targetUserId}: ${error.message}`,
        );
      }
    }
  }

  async sendInvite(
    communityId: string,
    senderId: string,
    targetUserId: string,
  ): Promise<void> {
    if (senderId === targetUserId) {
      throw new BadRequestException('Cannot invite yourself');
    }

    const community = await this.communityRepo.findById(communityId);
    if (!community) {
      throw new NotFoundException('Community not found');
    }

    // Check if already invited
    const existingInvite = await this.inviteRepo.findPendingInvite(
      communityId,
      targetUserId,
    );
    if (existingInvite) {
      throw new ConflictException('An invite is already pending for this user');
    }

    // Create the invite in DB
    const invite = await this.inviteRepo.create({
      communityId: community.id,
      senderId,
      receiverId: targetUserId,
      status: CommunityInviteStatus.PENDING,
      expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000), // 7 days
    });

    // Send chat message
    const { conversationId } =
      await this.chatService.getOrCreateDirectConversation(
        senderId,
        targetUserId,
      );

    const msg = await this.chatService.sendMessage(senderId, {
      conversationId,
      type: MessageType.COMMUNITY_INVITE,
      text: `Join ${community.name} - ${community.description?.slice(0, 60) || 'An adventurous community'}...`,
      clientMessageId: randomUUID(),
      metadata: {
        inviteId: invite.id,
        communityId: community.id,
        communityName: community.name,
        communityAvatar: community.avatar,
        communityCover: community.cover,
        memberCount: community.currentMemberCount,
        slug: community.slug,
        description: community.description,
      },
    });

    invite.conversationId = conversationId;
    invite.messageId = msg.id;
    await this.inviteRepo.save(invite);

    this.eventDispatcher.dispatchMemberInvited(
      communityId,
      senderId,
      targetUserId,
    );
  }

  async acceptInvite(inviteId: string, userId: string): Promise<void> {
    const invite = await this.inviteRepo.findById(inviteId);
    if (!invite) {
      throw new NotFoundException('Invite not found');
    }

    if (invite.receiverId !== userId) {
      throw new ForbiddenException(
        'You cannot accept an invite sent to someone else',
      );
    }

    if (invite.status === CommunityInviteStatus.ACCEPTED) {
      return; // Idempotent return if already accepted
    }

    if (invite.status !== CommunityInviteStatus.PENDING) {
      throw new BadRequestException(
        `Invite is already ${invite.status.toLowerCase()}`,
      );
    }

    if (invite.expiresAt && new Date() > invite.expiresAt) {
      await this.inviteRepo.updateStatus(
        inviteId,
        CommunityInviteStatus.EXPIRED,
      );
      throw new BadRequestException('This invite has expired');
    }

    // Join community using membership service (which also dispatches JOINED event)
    await this.membershipService.joinCommunity(invite.communityId, userId);

    // Remove invite from community_invites table upon acceptance as required
    await this.inviteRepo.delete(invite.id);
  }

  async declineInvite(inviteId: string, userId: string): Promise<void> {
    const invite = await this.inviteRepo.findById(inviteId);
    if (!invite) {
      throw new NotFoundException('Invite not found');
    }

    if (invite.receiverId !== userId) {
      throw new ForbiddenException(
        'You cannot decline an invite sent to someone else',
      );
    }

    if (invite.status !== CommunityInviteStatus.PENDING) {
      throw new BadRequestException(
        `Invite is already ${invite.status.toLowerCase()}`,
      );
    }

    // Remove invite from community_invites table upon declining as required
    await this.inviteRepo.delete(invite.id);
  }
}

import {
  BadRequestException,
  ConflictException,
  ForbiddenException,
  Injectable,
  Logger,
  NotFoundException,
  Inject,
  forwardRef,
} from '@nestjs/common';
import { DataSource } from 'typeorm';
import { CommunityEntity } from '../entities/community.entity';
import {
  CommunityMemberEntity,
  CommunityMemberStatus,
} from '../entities/community-member.entity';
import { CommunityStatisticsEntity } from '../entities/community-statistics.entity';
import { CommunityRepository } from '../repositories/community.repository';
import { CommunityMemberRepository } from '../repositories/community-member.repository';
import { CommunityBanRepository } from '../repositories/community-ban.repository';
import { CommunityRoleRepository } from '../repositories/community-role.repository';
import { CommunityEventDispatcher } from '../events/community-event.dispatcher';
import { CommunityPermissionService } from './community-permission.service';
import { CommunityModerationService } from './community-moderation.service';
import { CommunityRoleService } from './community-role.service';
import { CommunityAuditService } from './community-audit.service';
import { CommunityAuditAction } from '../entities/community-audit-log.entity';
import { CommunityPresenceTracker } from './community-presence.tracker';

@Injectable()
export class CommunityMembershipService {
  private readonly logger = new Logger(CommunityMembershipService.name);

  constructor(
    private readonly communityRepo: CommunityRepository,
    private readonly memberRepo: CommunityMemberRepository,
    private readonly banRepo: CommunityBanRepository,
    private readonly roleRepo: CommunityRoleRepository,
    private readonly eventDispatcher: CommunityEventDispatcher,
    private readonly permissionService: CommunityPermissionService,
    private readonly moderationService: CommunityModerationService,
    private readonly roleService: CommunityRoleService,
    private readonly auditService: CommunityAuditService,
    private readonly dataSource: DataSource,
    @Inject(forwardRef(() => CommunityPresenceTracker))
    private readonly presenceTracker: CommunityPresenceTracker,
  ) {}

  private async resolveCommunityId(communityIdOrSlug: string): Promise<string> {
    const id = await this.communityRepo.resolveId(communityIdOrSlug);
    if (!id) throw new NotFoundException('Community not found');
    return id;
  }

  async getMembers(communityIdOrSlug: string, includeGuests = true) {
    const communityId = await this.resolveCommunityId(communityIdOrSlug);

    const members = await this.memberRepo['repo']
      .createQueryBuilder('m')
      .leftJoinAndSelect('users', 'u', 'u.id = m.userId')
      .leftJoinAndSelect('community_roles', 'r', 'r.id = m.roleId')
      .where('m.communityId = :communityId', { communityId })
      .andWhere('m.status = :status', { status: CommunityMemberStatus.ACTIVE })
      .orderBy('m.joinedAt', 'ASC')
      .getRawAndEntities();

    // Map raw results back to the desired output structure
    const mappedMembers = members.entities.map((m, idx) => {
      const raw = members.raw[idx];
      return {
        id: m.id,
        userId: m.userId,
        username: raw.u_username,
        displayName: raw.u_displayName,
        avatarUrl: raw.u_avatarUrl,
        level: raw.u_level,
        roleId: m.roleId,
        roleName: raw.r_name || (m.isOwner ? 'OWNER' : 'MEMBER'),
        isOwner: m.isOwner,
        isMuted: m.isMuted,
        status: m.status,
        joinedAt: m.joinedAt,
        isGuest: false,
      };
    });

    if (includeGuests && this.presenceTracker) {
      const activeCohorts =
        await this.presenceTracker.getActiveCohorts(communityId);
      const guestCohorts = activeCohorts.filter((c) => c.isGuest);
      for (const guest of guestCohorts) {
        if (!mappedMembers.some((m) => m.userId === guest.userId)) {
          mappedMembers.push({
            id: `guest-${guest.userId}`,
            userId: guest.userId,
            username: guest.username,
            displayName: guest.displayName,
            avatarUrl: guest.avatarUrl,
            level: guest.level,
            roleId: 'GUEST',
            roleName: 'GUEST',
            isOwner: false,
            isMuted: false,
            status: 'ACTIVE' as any,
            joinedAt: new Date(guest.joinTime || Date.now()),
            isGuest: true,
          });
        }
      }
    }

    return mappedMembers;
  }

  async joinCommunity(
    communityId: string,
    userId: string,
  ): Promise<CommunityMemberEntity> {
    communityId = await this.resolveCommunityId(communityId);
    return this.dataSource.transaction(async (manager) => {
      const community = await manager.findOne(CommunityEntity, {
        where: { id: communityId },
        lock: { mode: 'pessimistic_write' },
      });
      if (!community) {
        throw new NotFoundException('Community not found');
      }

      const existingMember = await manager.findOne(CommunityMemberEntity, {
        where: { communityId, userId },
      });
      if (existingMember) {
        if (existingMember.status === CommunityMemberStatus.ACTIVE) {
          throw new ConflictException('User is already an active member');
        } else if (existingMember.status === CommunityMemberStatus.BANNED) {
          throw new ForbiddenException('User is banned from this community');
        }
      }

      const activeBan = await this.banRepo.findActiveBan(communityId, userId);
      if (activeBan) {
        throw new ForbiddenException(
          'User is currently banned from this community',
        );
      }

      if (community.currentMemberCount >= community.memberLimit) {
        throw new BadRequestException('Community has reached its member limit');
      }

      const memberRole = await this.roleRepo.findByName('MEMBER');
      let member: CommunityMemberEntity;

      if (existingMember) {
        existingMember.status = CommunityMemberStatus.ACTIVE;
        existingMember.roleId = memberRole?.id;
        member = await manager.save(existingMember);
      } else {
        member = manager.create(CommunityMemberEntity, {
          communityId,
          userId,
          roleId: memberRole?.id,
          status: CommunityMemberStatus.ACTIVE,
          isOwner: false,
        });
        member = await manager.save(member);
      }

      community.currentMemberCount += 1;
      await manager.save(community);
      await manager.update(
        CommunityStatisticsEntity,
        { communityId },
        { memberCount: community.currentMemberCount },
      );

      this.eventDispatcher.dispatchJoined(communityId, userId);
      return member;
    });
  }

  async leaveCommunity(communityId: string, userId: string): Promise<void> {
    communityId = await this.resolveCommunityId(communityId);
    return this.dataSource.transaction(async (manager) => {
      const community = await manager.findOne(CommunityEntity, {
        where: { id: communityId },
        lock: { mode: 'pessimistic_write' },
      });
      if (!community) {
        throw new NotFoundException('Community not found');
      }

      const member = await manager.findOne(CommunityMemberEntity, {
        where: { communityId, userId, status: CommunityMemberStatus.ACTIVE },
      });
      if (!member) {
        throw new BadRequestException('User is not an active member');
      }

      if (member.isOwner || community.ownerId === userId) {
        throw new BadRequestException(
          'Owner cannot leave community. Transfer ownership first.',
        );
      }

      member.status = CommunityMemberStatus.LEFT;
      await manager.save(member);

      community.currentMemberCount = Math.max(
        0,
        community.currentMemberCount - 1,
      );
      await manager.save(community);
      await manager.update(
        CommunityStatisticsEntity,
        { communityId },
        { memberCount: community.currentMemberCount },
      );

      this.eventDispatcher.dispatchLeft(communityId, userId);
    });
  }

  async kickMember(
    communityId: string,
    requesterId: string,
    targetUserId: string,
    reason?: string,
  ): Promise<void> {
    return this.moderationService.kickMember(
      communityId,
      requesterId,
      targetUserId,
      reason,
    );
  }

  async banMember(
    communityId: string,
    requesterId: string,
    targetUserId: string,
    reason?: string,
    permanent: boolean = true,
    expiresAt?: Date,
  ): Promise<void> {
    const durationMinutes = expiresAt
      ? Math.round((expiresAt.getTime() - Date.now()) / 60000)
      : undefined;
    return this.moderationService.banMember(
      communityId,
      requesterId,
      targetUserId,
      reason,
      permanent,
      durationMinutes,
    );
  }

  async muteMember(
    communityId: string,
    requesterId: string,
    targetUserId: string,
    durationMinutes: number,
    reason?: string,
  ): Promise<void> {
    await this.moderationService.muteMember(
      communityId,
      requesterId,
      targetUserId,
      durationMinutes,
      reason,
    );
  }

  async transferOwnership(
    communityId: string,
    currentOwnerId: string,
    newOwnerId: string,
  ): Promise<void> {
    communityId = await this.resolveCommunityId(communityId);
    if (currentOwnerId === newOwnerId) {
      throw new BadRequestException('Cannot transfer ownership to yourself');
    }

    return this.dataSource.transaction(async (manager) => {
      const community = await manager.findOne(CommunityEntity, {
        where: { id: communityId },
        lock: { mode: 'pessimistic_write' },
      });
      if (!community || community.ownerId !== currentOwnerId) {
        throw new ForbiddenException('You are not the owner of this community');
      }

      const oldOwner = await manager.findOne(CommunityMemberEntity, {
        where: { communityId, userId: currentOwnerId },
      });
      const newOwner = await manager.findOne(CommunityMemberEntity, {
        where: {
          communityId,
          userId: newOwnerId,
          status: CommunityMemberStatus.ACTIVE,
        },
      });

      if (!newOwner) {
        throw new BadRequestException(
          'New owner must be an active member of the community',
        );
      }

      const adminRole = await this.roleRepo.findByName('ADMIN');
      const ownerRole = await this.roleRepo.findByName('OWNER');

      // Update old owner to Admin
      if (oldOwner) {
        oldOwner.isOwner = false;
        oldOwner.roleId = adminRole?.id;
        await manager.save(oldOwner);
      }

      // Update new owner
      newOwner.isOwner = true;
      newOwner.roleId = ownerRole?.id;
      await manager.save(newOwner);

      // Update community entity
      community.ownerId = newOwnerId;
      await manager.save(community);

      this.eventDispatcher.dispatchOwnerTransferred(
        communityId,
        currentOwnerId,
        newOwnerId,
      );
      await this.auditService.logAction({
        communityId,
        actorId: currentOwnerId,
        targetUserId: newOwnerId,
        action: CommunityAuditAction.OWNERSHIP_TRANSFER,
        reason: 'Community ownership transferred to new owner',
        oldRole: 'MEMBER/ADMIN',
        newRole: 'OWNER',
      });
    });
  }

  async updateRole(
    communityId: string,
    requesterId: string,
    targetUserId: string,
    newRoleId: string,
  ): Promise<void> {
    await this.roleService.assignRole(
      communityId,
      requesterId,
      targetUserId,
      newRoleId,
    );
  }
}

import {
  BadRequestException,
  ForbiddenException,
  Injectable,
  Logger,
  NotFoundException,
} from '@nestjs/common';
import { DataSource } from 'typeorm';
import { CommunityEntity } from '../entities/community.entity';
import {
  CommunityMemberEntity,
  CommunityMemberStatus,
} from '../entities/community-member.entity';
import { CommunityStatisticsEntity } from '../entities/community-statistics.entity';
import { CommunityRepository } from '../repositories/community.repository';
import { CommunityMemberRepository } from '../repositories/community-member.repository';
import { CommunityBanRepository } from '../repositories/community-ban.repository';
import { CommunityRoleRepository } from '../repositories/community-role.repository';
import { CommunityPermissionService } from './community-permission.service';
import { CommunityAuditService } from './community-audit.service';
import { CommunityAuditAction } from '../entities/community-audit-log.entity';
import { CommunityEventDispatcher } from '../events/community-event.dispatcher';

@Injectable()
export class CommunityModerationService {
  private readonly logger = new Logger(CommunityModerationService.name);

  constructor(
    private readonly communityRepo: CommunityRepository,
    private readonly memberRepo: CommunityMemberRepository,
    private readonly banRepo: CommunityBanRepository,
    private readonly roleRepo: CommunityRoleRepository,
    private readonly permissionService: CommunityPermissionService,
    private readonly auditService: CommunityAuditService,
    private readonly eventDispatcher: CommunityEventDispatcher,
    private readonly dataSource: DataSource,
  ) {}

  /**
   * Issue an official warning to a member.
   */
  async warnMember(
    communityId: string,
    actorId: string,
    targetUserId: string,
    reason?: string,
  ): Promise<void> {
    const id = await this.permissionService.resolveCommunityId(communityId);
    const { member: actorMember, role: actorRole } =
      await this.permissionService.requirePermission(
        id,
        actorId,
        'member.mute',
      );

    const targetMember = await this.memberRepo.findByUserAndCommunity(
      targetUserId,
      id,
    );
    if (!targetMember || targetMember.status !== CommunityMemberStatus.ACTIVE) {
      throw new NotFoundException(
        'Target user is not an active member of this community',
      );
    }

    const targetRole = targetMember.roleId
      ? await this.roleRepo.findById(targetMember.roleId)
      : null;
    this.permissionService.enforceHierarchy(
      actorRole,
      actorMember.isOwner,
      targetRole,
      targetMember.isOwner,
      'warn',
    );

    const actionReason = reason || 'Community guideline warning';

    await this.auditService.logAction({
      communityId: id,
      actorId,
      targetUserId,
      action: CommunityAuditAction.MEMBER_WARN,
      reason: actionReason,
      metadata: { targetUsername: targetMember.nickname },
    });

    // Dispatch event so live UI/notification system picks up the warning immediately
    this.eventDispatcher.dispatchMemberWarned(
      id,
      targetUserId,
      actorId,
      actionReason,
    );
  }

  /**
   * Mute a member for a specific duration in minutes.
   */
  async muteMember(
    communityId: string,
    actorId: string,
    targetUserId: string,
    durationMinutes: number,
    reason?: string,
  ): Promise<CommunityMemberEntity> {
    const id = await this.permissionService.resolveCommunityId(communityId);
    const { member: actorMember, role: actorRole } =
      await this.permissionService.requirePermission(
        id,
        actorId,
        'member.mute',
      );

    const targetMember = await this.memberRepo.findByUserAndCommunity(
      targetUserId,
      id,
    );
    if (!targetMember || targetMember.status !== CommunityMemberStatus.ACTIVE) {
      throw new NotFoundException(
        'Target user is not an active member of this community',
      );
    }

    const targetRole = targetMember.roleId
      ? await this.roleRepo.findById(targetMember.roleId)
      : null;
    this.permissionService.enforceHierarchy(
      actorRole,
      actorMember.isOwner,
      targetRole,
      targetMember.isOwner,
      'mute',
    );

    const mutedUntil = new Date(Date.now() + durationMinutes * 60000);
    targetMember.isMuted = true;
    targetMember.mutedUntil = mutedUntil;
    const updated = await this.memberRepo.save(targetMember);

    await this.auditService.logAction({
      communityId: id,
      actorId,
      targetUserId,
      action: CommunityAuditAction.MEMBER_MUTE,
      reason: reason || `Muted for ${durationMinutes} minutes`,
      durationMinutes,
      metadata: { mutedUntil: mutedUntil.toISOString() },
    });

    this.eventDispatcher.dispatchMemberMuted(
      id,
      targetUserId,
      actorId,
      mutedUntil,
    );
    return updated;
  }

  /**
   * Unmute a member immediately.
   */
  async unmuteMember(
    communityId: string,
    actorId: string,
    targetUserId: string,
    reason?: string,
  ): Promise<CommunityMemberEntity> {
    const id = await this.permissionService.resolveCommunityId(communityId);
    const { member: actorMember, role: actorRole } =
      await this.permissionService.requirePermission(
        id,
        actorId,
        'member.mute',
      );

    const targetMember = await this.memberRepo.findByUserAndCommunity(
      targetUserId,
      id,
    );
    if (!targetMember) {
      throw new NotFoundException('Target user not found');
    }

    const targetRole = targetMember.roleId
      ? await this.roleRepo.findById(targetMember.roleId)
      : null;
    this.permissionService.enforceHierarchy(
      actorRole,
      actorMember.isOwner,
      targetRole,
      targetMember.isOwner,
      'unmute',
    );

    targetMember.isMuted = false;
    targetMember.mutedUntil = undefined;
    const updated = await this.memberRepo.save(targetMember);

    await this.auditService.logAction({
      communityId: id,
      actorId,
      targetUserId,
      action: CommunityAuditAction.MEMBER_UNMUTE,
      reason: reason || 'Mute lifted by moderator',
    });

    this.eventDispatcher.dispatchMemberUnmuted(
      id,
      targetUserId,
      actorId,
      reason,
    );
    return updated;
  }

  /**
   * Kick a member from the community. They can re-join anytime if not banned.
   */
  async kickMember(
    communityId: string,
    actorId: string,
    targetUserId: string,
    reason?: string,
  ): Promise<void> {
    const id = await this.permissionService.resolveCommunityId(communityId);
    const { member: actorMember, role: actorRole } =
      await this.permissionService.requirePermission(
        id,
        actorId,
        'member.kick',
      );

    return this.dataSource.transaction(async (manager) => {
      const target = await manager.findOne(CommunityMemberEntity, {
        where: {
          communityId: id,
          userId: targetUserId,
          status: CommunityMemberStatus.ACTIVE,
        },
      });
      if (!target) {
        throw new NotFoundException(
          'Target user is not an active member of this community',
        );
      }

      const targetRole = target.roleId
        ? await this.roleRepo.findById(target.roleId)
        : null;
      this.permissionService.enforceHierarchy(
        actorRole,
        actorMember.isOwner,
        targetRole,
        target.isOwner,
        'kick',
      );

      const oldRoleName =
        targetRole?.displayName || targetRole?.name || 'MEMBER';
      target.status = CommunityMemberStatus.KICKED;
      await manager.save(target);

      const community = await manager.findOne(CommunityEntity, {
        where: { id },
        lock: { mode: 'pessimistic_write' },
      });
      if (community) {
        community.currentMemberCount = Math.max(
          0,
          community.currentMemberCount - 1,
        );
        await manager.save(community);
        await manager.update(
          CommunityStatisticsEntity,
          { communityId: id },
          { memberCount: community.currentMemberCount },
        );
      }

      await this.auditService.logAction({
        communityId: id,
        actorId,
        targetUserId,
        action: CommunityAuditAction.MEMBER_KICK,
        reason: reason || 'Kicked by moderator',
        oldRole: oldRoleName,
      });

      this.eventDispatcher.dispatchMemberKicked(id, targetUserId, actorId);
    });
  }

  /**
   * Ban a member temporarily or permanently.
   */
  async banMember(
    communityId: string,
    actorId: string,
    targetUserId: string,
    reason?: string,
    permanent = true,
    durationMinutes?: number,
  ): Promise<void> {
    const id = await this.permissionService.resolveCommunityId(communityId);
    const { member: actorMember, role: actorRole } =
      await this.permissionService.requirePermission(id, actorId, 'member.ban');

    return this.dataSource.transaction(async (manager) => {
      const target = await manager.findOne(CommunityMemberEntity, {
        where: { communityId: id, userId: targetUserId },
      });
      const targetRole = target?.roleId
        ? await this.roleRepo.findById(target.roleId)
        : null;
      this.permissionService.enforceHierarchy(
        actorRole,
        actorMember.isOwner,
        targetRole,
        target?.isOwner ?? false,
        'ban',
      );

      const oldRoleName =
        targetRole?.displayName ||
        targetRole?.name ||
        (target?.status === CommunityMemberStatus.ACTIVE ? 'MEMBER' : 'NONE');

      if (target && target.status === CommunityMemberStatus.ACTIVE) {
        target.status = CommunityMemberStatus.BANNED;
        await manager.save(target);

        const community = await manager.findOne(CommunityEntity, {
          where: { id },
          lock: { mode: 'pessimistic_write' },
        });
        if (community) {
          community.currentMemberCount = Math.max(
            0,
            community.currentMemberCount - 1,
          );
          await manager.save(community);
          await manager.update(
            CommunityStatisticsEntity,
            { communityId: id },
            { memberCount: community.currentMemberCount },
          );
        }
      } else if (target) {
        target.status = CommunityMemberStatus.BANNED;
        await manager.save(target);
      } else {
        // Create banned member record if user never joined before
        const newMember = manager.create(CommunityMemberEntity, {
          communityId: id,
          userId: targetUserId,
          status: CommunityMemberStatus.BANNED,
          isOwner: false,
        });
        await manager.save(newMember);
      }

      const expiresAt =
        !permanent && durationMinutes
          ? new Date(Date.now() + durationMinutes * 60000)
          : undefined;
      await this.banRepo.create({
        communityId: id,
        userId: targetUserId,
        bannedBy: actorId,
        reason: reason || 'Banned from community',
        permanent,
        expiresAt,
      });

      await this.auditService.logAction({
        communityId: id,
        actorId,
        targetUserId,
        action: CommunityAuditAction.MEMBER_BAN,
        reason:
          reason ||
          (permanent ? 'Permanent Ban' : `Temporary Ban (${durationMinutes}m)`),
        oldRole: oldRoleName,
        durationMinutes: permanent ? undefined : durationMinutes,
        metadata: { permanent, expiresAt: expiresAt?.toISOString() },
      });

      this.eventDispatcher.dispatchMemberBanned(id, targetUserId, actorId);
    });
  }

  /**
   * Unban a member so they can re-join the community.
   */
  async unbanMember(
    communityId: string,
    actorId: string,
    targetUserId: string,
    reason?: string,
  ): Promise<void> {
    const id = await this.permissionService.resolveCommunityId(communityId);
    await this.permissionService.requirePermission(id, actorId, 'member.ban');

    return this.dataSource.transaction(async (manager) => {
      const activeBan = await this.banRepo.findActiveBan(id, targetUserId);
      if (activeBan) {
        await manager.delete(this.banRepo.target, { id: activeBan.id });
      }

      const member = await manager.findOne(CommunityMemberEntity, {
        where: { communityId: id, userId: targetUserId },
      });
      if (member && member.status === CommunityMemberStatus.BANNED) {
        member.status = CommunityMemberStatus.LEFT; // Reset to left so they can join again cleanly
        await manager.save(member);
      }

      await this.auditService.logAction({
        communityId: id,
        actorId,
        targetUserId,
        action: CommunityAuditAction.MEMBER_UNBAN,
        reason: reason || 'Ban revoked by moderator',
      });

      this.eventDispatcher.dispatchMemberUnbanned(
        id,
        targetUserId,
        actorId,
        reason,
      );
    });
  }

  /**
   * Get complete moderation & infractions history for a member.
   */
  async getMemberHistory(
    communityId: string,
    targetUserId: string,
  ): Promise<{
    auditLogs: any[];
    activeBan: any | null;
    warningsCount: number;
    mutesCount: number;
  }> {
    const id = await this.permissionService.resolveCommunityId(communityId);
    const { items: auditLogs } = await this.auditService.getLogs(id, {
      targetUserId,
      limit: 50,
    });
    const activeBan = await this.banRepo.findActiveBan(id, targetUserId);

    let warningsCount = 0;
    let mutesCount = 0;
    for (const log of auditLogs) {
      if (log.action === CommunityAuditAction.MEMBER_WARN) warningsCount++;
      if (log.action === CommunityAuditAction.MEMBER_MUTE) mutesCount++;
    }

    return { auditLogs, activeBan, warningsCount, mutesCount };
  }
}

import { Injectable, Logger, OnModuleInit } from '@nestjs/common';
import { ChatEventDispatcher } from '../../chat/services/chat-event.dispatcher';
import { ChatGateway } from '../../chat/chat.gateway';
import { CommunityMemberRepository } from '../repositories/community-member.repository';
import { CommunityMemberStatus } from '../entities/community-member.entity';
import {
  CommunityEventDispatcher,
  CommunityEvents,
} from '../events/community-event.dispatcher';
import { CommunityRedisPresenceService } from './community-redis-presence.service';
import { COMMUNITY_RANKING_CONFIG } from '../config/community-ranking.config';

@Injectable()
export class CommunityPresenceTracker implements OnModuleInit {
  private readonly logger = new Logger(CommunityPresenceTracker.name);

  // communityId -> Set of online user IDs
  private readonly communityOnlineMap = new Map<string, Set<string>>();

  // communityId -> boolean (isLive)
  private readonly communityLiveState = new Map<string, boolean>();

  // communityId -> Map<userId, user info>
  private readonly lobbyCohorts = new Map<string, Map<string, any>>();
  // communityId -> Map<userId, Set<socketId>>
  private readonly communityUserSockets = new Map<
    string,
    Map<string, Set<string>>
  >();

  // socketId -> communityId
  private readonly socketLobbyMap = new Map<string, string>();

  // Timeout for debouncing disconnects
  private readonly disconnectTimers = new Map<string, NodeJS.Timeout>();

  constructor(
    private readonly chatDispatcher: ChatEventDispatcher,
    private readonly chatGateway: ChatGateway,
    private readonly memberRepo: CommunityMemberRepository,
    private readonly communityDispatcher: CommunityEventDispatcher,
    private readonly redisPresence: CommunityRedisPresenceService,
  ) {}

  onModuleInit() {
    this.chatDispatcher.subscribe(
      'USER_CONNECTED',
      this.handleUserConnected.bind(this),
    );
    this.chatDispatcher.subscribe(
      'USER_DISCONNECTED',
      this.handleUserDisconnected.bind(this),
    );
    this.chatDispatcher.subscribe(
      'COMMUNITY_JOIN_LOBBY' as any,
      this.handleJoinLobby.bind(this),
    );
    this.chatDispatcher.subscribe(
      'COMMUNITY_LEAVE_LOBBY' as any,
      this.handleLeaveLobby.bind(this),
    );

    this.communityDispatcher.on(CommunityEvents.JOINED, (payload) => {
      this.broadcastCommunityUpdate(payload.communityId);
      this.broadcastActiveCohort(payload.communityId);
    });
    this.communityDispatcher.on(CommunityEvents.LEFT, (payload) => {
      this.broadcastCommunityUpdate(payload.communityId);
      this.removeUserSocketFromLobby(payload.communityId, payload.userId);
    });
    this.communityDispatcher.on(CommunityEvents.MEMBER_KICKED, (payload) => {
      this.broadcastCommunityUpdate(payload.communityId);
      this.removeUserSocketFromLobby(payload.communityId, payload.userId);
    });
    this.communityDispatcher.on(CommunityEvents.MEMBER_BANNED, (payload) => {
      this.broadcastCommunityUpdate(payload.communityId);
      this.removeUserSocketFromLobby(payload.communityId, payload.userId);
    });
    this.communityDispatcher.on(CommunityEvents.ROLE_CHANGED, (payload) =>
      this.broadcastCommunityUpdate(payload.communityId),
    );
    this.communityDispatcher.on(CommunityEvents.UPDATED, (payload) =>
      this.broadcastCommunityUpdate(payload.communityId),
    );
    this.communityDispatcher.on(CommunityEvents.MEMBER_INVITED, (payload) =>
      this.broadcastCommunityUpdate(payload.communityId),
    );
  }

  private broadcastCommunityUpdate(communityId: string) {
    if (!communityId) return;
    this.chatGateway.server?.emit('COMMUNITY_UPDATED', { communityId });
  }

  private handleJoinLobby(payload: {
    communityId: string;
    userId: string;
    user: any;
    socketId: string;
  }) {
    const { communityId, userId, user, socketId } = payload;
    if (!communityId || !userId || !socketId) return;

    const timerId = `${userId}:${communityId}`;
    if (this.disconnectTimers.has(timerId)) {
      clearTimeout(this.disconnectTimers.get(timerId));
      this.disconnectTimers.delete(timerId);
    }

    if (!this.communityUserSockets.has(communityId)) {
      this.communityUserSockets.set(communityId, new Map());
    }
    const userSockets = this.communityUserSockets.get(communityId)!;
    if (!userSockets.has(userId)) {
      userSockets.set(userId, new Set());
    }
    userSockets.get(userId)!.add(socketId);
    this.socketLobbyMap.set(socketId, communityId);

    if (!this.lobbyCohorts.has(communityId)) {
      this.lobbyCohorts.set(communityId, new Map());
    }
    const cohortUser = {
      userId,
      displayName: user?.displayName || user?.username || 'Traveler',
      username: user?.username || 'traveler',
      avatarUrl:
        user?.avatarUrl ||
        'https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=200',
      roleName:
        user?.roleName ||
        (user?.isOwner ? 'OWNER' : user?.isMember ? 'MEMBER' : 'GUEST'),
      isGuest:
        user?.roleName === 'GUEST' || (!user?.isOwner && !user?.isMember),
      status: user?.status || 'Active Now',
      joinTime: Date.now(),
      connectionQuality: 'Excellent' as const,
      level: user?.level || 1,
    };
    this.lobbyCohorts.get(communityId)!.set(userId, cohortUser);
    this.redisPresence
      .enterPresenceSession(communityId, cohortUser, socketId)
      .then((count) => {
        this.checkAndBroadcastLiveState(communityId, count);
      });
    this.broadcastActiveCohort(communityId);
  }

  private handleLeaveLobby(payload: {
    communityId: string;
    userId: string;
    socketId?: string;
  }) {
    const { communityId, userId, socketId } = payload;
    if (!communityId || !userId) return;
    this.removeUserSocketFromLobby(communityId, userId, socketId);
  }

  private removeUserSocketFromLobby(
    communityId: string,
    userId: string,
    socketId?: string,
  ) {
    const userSockets = this.communityUserSockets.get(communityId);
    if (!userSockets || !userSockets.has(userId)) return;

    if (socketId) {
      userSockets.get(userId)!.delete(socketId);
      this.socketLobbyMap.delete(socketId);
    } else {
      userSockets.get(userId)!.clear();
    }

    if (userSockets.get(userId)!.size === 0) {
      const timerId = `${userId}:${communityId}`;
      if (this.disconnectTimers.has(timerId)) {
        clearTimeout(this.disconnectTimers.get(timerId));
      }

      const timer = setTimeout(() => {
        const currentSockets = this.communityUserSockets
          .get(communityId)
          ?.get(userId);
        if (!currentSockets || currentSockets.size === 0) {
          this.communityUserSockets.get(communityId)?.delete(userId);
          if (this.lobbyCohorts.has(communityId)) {
            this.lobbyCohorts.get(communityId)!.delete(userId);
            this.broadcastActiveCohort(communityId);
          }
          this.redisPresence
            .leavePresenceSession(communityId, userId)
            .then((count) => {
              this.checkAndBroadcastLiveState(communityId, count);
            });
        }
        this.disconnectTimers.delete(timerId);
      }, 3000);

      this.disconnectTimers.set(timerId, timer);
    }
  }

  async getActiveCohorts(communityId: string) {
    const redisCohorts = await this.redisPresence.getActiveCohorts(communityId);
    if (redisCohorts && redisCohorts.length > 0) return redisCohorts;
    const cohortMap = this.lobbyCohorts.get(communityId);
    return cohortMap ? Array.from(cohortMap.values()) : [];
  }

  async pulseHeartbeat(communityId: string, userId: string) {
    return this.redisPresence.pulseHeartbeat(communityId, userId);
  }

  private broadcastActiveCohort(communityId: string) {
    const cohortMap = this.lobbyCohorts.get(communityId);
    const activeCohort = cohortMap ? Array.from(cohortMap.values()) : [];
    this.chatGateway.server
      ?.to(`community:${communityId}`)
      .emit('community:active-cohort-updated', {
        communityId,
        activeCohort,
      });
  }

  private async handleUserConnected(payload: {
    userId: string;
    socketId: string;
  }) {
    try {
      const allMembers = await this.memberRepo.findByUser(payload.userId);
      const members = allMembers.filter(
        (m) => m.status === CommunityMemberStatus.ACTIVE,
      );

      for (const member of members) {
        const communityId = member.communityId;

        if (!this.communityOnlineMap.has(communityId)) {
          this.communityOnlineMap.set(communityId, new Set());
        }

        const onlineSet = this.communityOnlineMap.get(communityId)!;
        const previouslyOnline = onlineSet.size;

        onlineSet.add(payload.userId);

        const currentlyOnline = onlineSet.size;

        if (previouslyOnline !== currentlyOnline) {
          this.checkAndBroadcastLiveState(communityId, currentlyOnline);
        }
      }
    } catch (error) {
      this.logger.error(
        `Error handling user connected for presence tracker: ${error.message}`,
      );
    }
  }

  private async handleUserDisconnected(payload: {
    userId: string;
    socketId: string;
    isStillOnline: boolean;
  }) {
    const { userId, socketId, isStillOnline } = payload;

    // Clean up lobby presence for this socket immediately
    const communityId = this.socketLobbyMap.get(socketId);
    if (communityId) {
      this.removeUserSocketFromLobby(communityId, userId, socketId);
    }

    if (isStillOnline) return;

    try {
      const allMembers = await this.memberRepo.findByUser(payload.userId);
      const members = allMembers.filter(
        (m) => m.status === CommunityMemberStatus.ACTIVE,
      );

      for (const member of members) {
        const communityId = member.communityId;

        if (this.communityOnlineMap.has(communityId)) {
          const onlineSet = this.communityOnlineMap.get(communityId)!;
          const previouslyOnline = onlineSet.size;

          onlineSet.delete(payload.userId);

          const currentlyOnline = onlineSet.size;

          if (previouslyOnline !== currentlyOnline) {
            this.checkAndBroadcastLiveState(communityId, currentlyOnline);
          }
        }
      }
    } catch (error: any) {
      this.logger.error(
        `Error handling user disconnected for presence tracker: ${error.message}`,
      );
    }
  }

  private checkAndBroadcastLiveState(communityId: string, onlineCount: number) {
    const minActive = COMMUNITY_RANKING_CONFIG.thresholds.minOnlineForActive;
    const isLive = onlineCount >= minActive;
    const previouslyLive = this.communityLiveState.get(communityId) || false;

    this.communityLiveState.set(communityId, isLive);

    this.chatGateway.server?.emit('COMMUNITY_LIVE_STATE_CHANGED', {
      communityId,
      isLive,
      onlineMemberCount: onlineCount,
    });

    this.chatGateway.server?.emit('community:online:count', {
      communityId,
      onlineMemberCount: onlineCount,
      isLive,
    });

    if (!previouslyLive && isLive) {
      this.chatGateway.server?.emit('community:activated', {
        communityId,
        onlineMemberCount: onlineCount,
      });
      this.chatGateway.server?.emit('discovery:cluster:changed', {
        communityId,
        isLive: true,
      });
    } else if (previouslyLive && !isLive) {
      this.chatGateway.server?.emit('community:deactivated', {
        communityId,
        onlineMemberCount: onlineCount,
      });
      this.chatGateway.server?.emit('discovery:cluster:changed', {
        communityId,
        isLive: false,
      });
    }
  }

  /**
   * Used by CommunityDiscoveryService to inject live stats into query results
   */
  getCommunityLiveStats(communityId: string): {
    isLive: boolean;
    onlineMemberCount: number;
  } {
    const minActive = COMMUNITY_RANKING_CONFIG.thresholds.minOnlineForActive;
    const count = this.communityOnlineMap.get(communityId)?.size || 0;
    return {
      isLive: count >= minActive,
      onlineMemberCount: count,
    };
  }
}

import { Injectable, Logger, OnModuleInit, Optional } from '@nestjs/common';
import { RedisService } from '../../redis/redis-core.service';
import { COMMUNITY_RANKING_CONFIG } from '../config/community-ranking.config';

export interface ActiveCohortUser {
  userId: string;
  displayName: string;
  username: string;
  avatarUrl: string;
  roleName: string;
  isGuest?: boolean;
  status?: string;
  currentActivity?: string;
  joinTime?: number;
  connectionQuality?: 'Excellent' | 'Good' | 'Fair';
  isTyping?: boolean;
}

@Injectable()
export class CommunityRedisPresenceService implements OnModuleInit {
  private readonly logger = new Logger(CommunityRedisPresenceService.name);

  // Fallback in-memory structures if Upstash/Redis connection is pending
  private readonly fallbackOnlineMap = new Map<string, Set<string>>();
  private readonly fallbackCohorts = new Map<
    string,
    Map<string, ActiveCohortUser>
  >();

  constructor(@Optional() private readonly redisService?: RedisService) {}

  onModuleInit() {
    if (this.redisService) {
    } else {
      this.logger.warn(
        'RedisService not injected. Using high-performance in-memory presence fallback.',
      );
    }
  }

  /**
   * Registers a user or guest joining a community presence session / active cohort.
   * Updates Redis Sets, Sorted Sets, and sets heartbeat TTL.
   */
  async enterPresenceSession(
    communityId: string,
    user: ActiveCohortUser,
    socketId?: string,
  ): Promise<number> {
    const ttl = COMMUNITY_RANKING_CONFIG.thresholds.presenceTtlSeconds;
    const client = this.redisService?.client;

    if (client && client.status === 'ready') {
      try {
        const userKey = `presence:user:${user.userId}`;
        const onlineSetKey = `presence:community:${communityId}:online`;
        const cohortHashKey = `presence:room:community:${communityId}:cohorts`;
        const rankingZSetKey = `presence:community:ranking:online`;

        // 1. Update user presence TTL
        await client.hset(userKey, {
          status: user.status || 'Active Now',
          lastSeen: Date.now().toString(),
          currentCommunityId: communityId,
        });
        await client.expire(userKey, ttl);

        // 2. Add user to community online set
        await client.sadd(onlineSetKey, user.userId);
        await client.expire(onlineSetKey, ttl * 10); // Keep set active longer than individual sessions

        // 3. Store active cohort user payload in room hash
        await client.hset(cohortHashKey, user.userId, JSON.stringify(user));

        // 4. Update online count in Sorted Set without scanning keys
        const count = await client.scard(onlineSetKey);
        await client.zadd(rankingZSetKey, count, communityId);

        return count;
      } catch (err: any) {
        this.logger.error(
          `Redis enterPresenceSession error: ${err.message}. Falling back to memory.`,
        );
      }
    }

    // In-memory fallback
    if (!this.fallbackOnlineMap.has(communityId)) {
      this.fallbackOnlineMap.set(communityId, new Set());
    }
    this.fallbackOnlineMap.get(communityId)!.add(user.userId);

    if (!this.fallbackCohorts.has(communityId)) {
      this.fallbackCohorts.set(communityId, new Map());
    }
    this.fallbackCohorts.get(communityId)!.set(user.userId, user);

    return this.fallbackOnlineMap.get(communityId)!.size;
  }

  /**
   * Removes a user session when they leave or disconnect.
   */
  async leavePresenceSession(
    communityId: string,
    userId: string,
  ): Promise<number> {
    const client = this.redisService?.client;

    if (client && client.status === 'ready') {
      try {
        const onlineSetKey = `presence:community:${communityId}:online`;
        const cohortHashKey = `presence:room:community:${communityId}:cohorts`;
        const rankingZSetKey = `presence:community:ranking:online`;

        await client.srem(onlineSetKey, userId);
        await client.hdel(cohortHashKey, userId);

        const count = await client.scard(onlineSetKey);
        if (count <= 0) {
          await client.zrem(rankingZSetKey, communityId);
        } else {
          await client.zadd(rankingZSetKey, count, communityId);
        }
        return count;
      } catch (err: any) {
        this.logger.error(
          `Redis leavePresenceSession error: ${err.message}. Falling back to memory.`,
        );
      }
    }

    // In-memory fallback
    const onlineSet = this.fallbackOnlineMap.get(communityId);
    if (onlineSet) {
      onlineSet.delete(userId);
    }
    const cohortMap = this.fallbackCohorts.get(communityId);
    if (cohortMap) {
      cohortMap.delete(userId);
    }
    return onlineSet ? onlineSet.size : 0;
  }

  /**
   * Heartbeat pulse to refresh TTL and keep session active without polling
   */
  async pulseHeartbeat(communityId: string, userId: string): Promise<boolean> {
    const ttl = COMMUNITY_RANKING_CONFIG.thresholds.presenceTtlSeconds;
    const client = this.redisService?.client;

    if (client && client.status === 'ready') {
      try {
        const userKey = `presence:user:${userId}`;
        const onlineSetKey = `presence:community:${communityId}:online`;
        await client.expire(userKey, ttl);
        await client.expire(onlineSetKey, ttl * 10);
        return true;
      } catch (e) {
        // ignore
      }
    }
    return true;
  }

  /**
   * Retrieves current online count for a community in O(1)
   */
  async getOnlineCount(communityId: string): Promise<number> {
    const client = this.redisService?.client;
    if (client && client.status === 'ready') {
      try {
        const count = await client.scard(
          `presence:community:${communityId}:online`,
        );
        return count;
      } catch (e) {
        // ignore
      }
    }
    return this.fallbackOnlineMap.get(communityId)?.size || 0;
  }

  /**
   * Retrieves active cohort details (including guests)
   */
  async getActiveCohorts(communityId: string): Promise<ActiveCohortUser[]> {
    const client = this.redisService?.client;
    if (client && client.status === 'ready') {
      try {
        const cohortHashKey = `presence:room:community:${communityId}:cohorts`;
        const rawValues = await client.hvals(cohortHashKey);
        return rawValues.map((v) => JSON.parse(v));
      } catch (e) {
        // ignore
      }
    }
    const map = this.fallbackCohorts.get(communityId);
    return map ? Array.from(map.values()) : [];
  }
}

